window.__QUIZ_SUBJECT__=[{"id": "theory>Civic Education>2014>1>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "What are values?", "images": [], "marking_scheme": "Values signify norms and behaviour traits which are generally accepted as being of great worth in the society. In other words, values are standard citizens which determine how the people of a society, nation or state think and relate with one another.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2014>1>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "State six importance of values.", "images": [], "marking_scheme": "i) Values promote self-reliance in society, thus creating employment opportunities for citizens.  ii) Values serves as a criteria or measures for the judgement of individuals in the society.  iii) Value help to determine and control the behaviour of individuals in the society.  iv) Values help us to develop respect for other people's ways of life.  v)Values encourages tolerance and friendship among people in the society.  vi) Values lead to actions which promote development in the society.  vii) Values ultimately promote growth and development in the society.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2014>2>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP EDUCATION", "question": "Explain the term citizenship education.", "images": [], "marking_scheme": "Citizenship education is a process of enlightening or training citizens on their rights and responsibility in the society.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2014>2>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "State four reasons for effective citizenship education of Nigerian youths.", "images": [], "marking_scheme": "i) It helps to sensitive Nigerian Youths on their duties and rights as citizens.  ii) It helps to inculcate the right values and attitudes into the youths for the development of the society.   iii) It helps to produce responsible, well-informed and self-reliant Nigerian youths.  iv) It helps to encourage National Integration and nation building.  v) It helps to prepare the youths for future leadership roles.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2014>3>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)", "question": "What is the meaning of Universal Declaration of Human Rights (UDHRY)?", "images": [], "marking_scheme": "It was adopted by the General Assembly of the United Nations Organisation on December 10, 1948 in Paris, France. It refers to global proclamation specifying the rights of Individuals. The charter consists of thirty (30) articles on Human rights.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2014>3>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND IDENTIFICATION OF THE SEVEN CORE FREEDOMS OF UDHR", "question": "Highlight any six core rights or freedom in the Universal Declaration of Human Rights of 1948.", "images": [], "marking_scheme": "i. The right to freedom of movement and residence within the borders of each state.  ii. Right to life, liberty and security of person.  iii. The right to freedom of thought, conscience and religion.  iv. The right to freedom of opinion and expression.  v. The right to freedom of peaceful assembly association.  vi. All human beings are born free and equal in dignity and rights.  vii. The right to recognition everywhere as a person before the law.", "marks": "12", "difficulty": "3"}, {"id": "theory>Civic Education>2014>4>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : MEANING OF HUMAN TRAFFICKING", "question": "Define human trafficking.", "images": [], "marking_scheme": "Human trafficking is defined as illegal business in the sale and transportation of human beings for economic and selfish purposes usually unsuspecting victims are lured away into forced labour, prostitution and other forms of abuse. It also refers to the recruitment, transportation, harbouring or receipt of persons by deception, force or threat of harm for the purpose of exploitation.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2014>4>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "State six causes of human trafficking in Nigeria.", "images": [], "marking_scheme": "i. Unemployment  ii. Poverty  iii. Disorientation of values/moral decadence in society  iv. Greed and get rich quick attitude  v. Corruption in the society  vi. Political instability  vii. Lack of education  viii. Conflict/wars", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2014>5>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : MEANING OF DRUG ABUSE", "question": "What is drug abuse?", "images": [], "marking_scheme": "Drug abuse refers to the use of drugs through self-medication or without due medical prescription and administration. It is the indiscriminate use of any drug i.e marijuana (Indian hemp), heroine, morphine and so on.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2014>5>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Highlight six ways by which drug abuse can be curbed in the society.", "images": [], "marking_scheme": "i. Access to hard drugs should be controlled by those authority.  ii. Establishment of drug control agencies e.g NDLEA, NAFDAC and NGOs.  iii. Proper family up-bring should be encouraged so as to curtail undue influence on children  iv. Youth should be taught moral and religious principles  v. Youth should be encouraged to resist negative peer pressure  vi. Good knowledge of drugs by individuals and as the public should be encouraged  vii. Stiff penalty should be applied for drug related offences.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2014>6>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "List five consequencies of cultism.", "images": [], "marking_scheme": "i. Violence and social instability  ii. Breakdown of law & order  iii. Disruption of academic activities  iv. Drug addiction and related health problems  v. Destroys the future of the youths  vi. Embarrassment for families and parents.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2014>6>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Highlight five ways by which cultism can be prevented.", "images": [], "marking_scheme": "i. Parents should show good example to their children  ii. The teaching and learning environment should be conducive  iii. Students should be encouraged to join religious groups and develop the fear of God  iv. Parents should pay more attention to their children's upbring  v. Educational Institutions and the government should enact very stiff laws against cultist and strictly enforce such laws  vi. Counseling units in schools should be more effective in assisting cultists to renounce their membership.", "marks": "10", "difficulty": "2"}, {"id": "theory>Civic Education>2014>7>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "Mention five characteristics of democracy.", "images": [], "marking_scheme": "i. Freedom of association and groups  ii. Equal political right  iii. Independent judiciary  iv. Tolerance of opposition  v. Constitutional governance  vi. Free and fair election", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2014>7>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "State five ways by which the practice of democracy can contribute to national development.", "images": [], "marking_scheme": "i. Democracy promote political stability which enhances national development  ii. Democracy promotes transparency and accountability  iii. Democracy promotes poverty alleviation  iv. It leads to employment generation  v. It facilitates effective participation of citizens in governance  vi. It promotes rule of law and constitutionalism.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2014>8>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "Explain the term 'political apathy'.", "images": [], "marking_scheme": "Political apathy can be defined as the lack of interest in political programmers' of a country due to one reason or the other, political apathy is said to have taken place e.g the cold feet Nigerians often develop during elections which makes them not to go out to vote could be regarded as political apathy.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2014>8>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "State three consequences of political apathy.", "images": [], "marking_scheme": "i. Slow pace of political development   ii. It results to corruption  iii. Lack of accountability  iv. Emergence of undemocratic government.", "marks": "6", "difficulty": "2"}, {"id": "theory>Civic Education>2014>8>c", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WAYS OF DISCOURAGING POLITICAL APATHY", "question": "Highlight three ways through which political apathy can be discouraged.", "images": [], "marking_scheme": "i. Making leaders accountable to the people who elected them  ii. Defending the fundamental human rights of citizens.  iii. Encourage popular participation in elections  iv. Non-partisan judiciary", "marks": "6", "difficulty": "2"}, {"id": "theory>Civic Education>2014>9>a", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION", "question": "Define the term 'popular participation'.", "images": [], "marking_scheme": "Popular participation refers to the active involvement of citizens in the socio-political activities of a country. It also refers to the procedure of involving majority of the citizens of a country in the decision making processes, especially on issues that affect the welfare of the generality of the populace.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2014>9>b", "subject": "Civic Education", "year": "2014", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY", "question": "State six reasons for popular participation in the society.", "images": [], "marking_scheme": "i. Influence the direction of government policies  ii. Improve the quality of governance  iii. Enhance confidence of the people to hold government accountable  iv. Create greater opportunities for citizens  v. Promote popular consciousness  vi. Institutionalize responsive and responsible government  vii. Enhance development  viii. Foster political stability.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2015>1>a", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : FEATURES OF LAW AND ORDER", "question": "List six characteristics of a society exhibiting law and order.", "images": [], "marking_scheme": "- Obedience to constituted authority  - Peaceful protest  - Constitutionalism  - Queuing culture  - Religious tolerance  - Peaceful coexistence  - Peaceful conduct of elections  - Absence of wars and civil strife", "marks": "12", "difficulty": "1"}, {"id": "theory>Civic Education>2015>1>b", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : FEATURES OF LAW AND ORDER", "question": "Explain any three of the characteristics mentioned in (a).", "images": [], "marking_scheme": "-  Peaceful Co-existence:  Among individuals, clans, tribes, ethnic groups and religious institutions that make up the society is the manifestation of the existence of law & order.    -  Absence of Wars and Civil Strife:  Wars and strife are generally absent in society exhibiting law and order. The breakdown of law and order makes the society ungovernable.    -  Peaceful Conduct of Elections:  Electioneering activities such as campaigns, voting and announcement of result e.t.c.    -  Tolerance of Oppositions:  There is tolerance of opposition or opposing views in the society where law and order are exhibited.    -  Religious Tolerance:  Adherents of different religious in the society tolerate the views, teachings and preaching of others which prevent sectarian crises.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2015>2>a", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "Define national integration.", "images": [], "marking_scheme": "National Integration is a process of creating a sense of national consciousness, uniqueness of identity and loyalty among people with different socio-cultural background into a single territorial political society.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2015>2>b", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "State four ways through which national integration can be promoted in Nigeria.", "images": [], "marking_scheme": "i. Strengthening the National Youth Service Corps (NYSC) scheme  ii. Providing equal access to representation in government  iii. Promoting public education for national integration  iv. Providing equal access to education  v. Promoting equal economic opportunities  vi. Promotion of cultural re-orientation/awareness  vii. Organising national cultural festivals  viii. Encouraging Nigerians to be patriotic  ix. Formation of political parties with national outlook", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2015>3>a", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : IDENTIFICATION OF LOCAL AND WORLD CIVIC PROBLEMS", "question": "Mention any six civic problems in the society.", "images": [], "marking_scheme": "- Human trafficking  - Bad roads  - Corruption  - Political apathy  - Examination malpractices  - Over population  - Drug abuse   - Poverty  - Vandalisation of government property  - Diseases e.g HIV/AIDS, ebola etc.", "marks": "12", "difficulty": "1"}, {"id": "theory>Civic Education>2015>3>b", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : IDENTIFICATION OF LOCAL AND WORLD CIVIC PROBLEMS", "question": "State three ways in which Nigerian citizens can be engaged in solving civic problems.", "images": [], "marking_scheme": "- Popular participation in the society should be encouraged.  - They should monitor and evaluate programmes, policies and projects targeted at solving social problems.  - They should engage in collaborative efforts with other stakeholders to solve societal problems.  - Citizens should develop positive disposition to civic/societal problems-solving.  - Citizens can identify and report existing and emerging civic problems.  - Government should create employment opportunities for citizens.  - Citizens should be involved in awareness programmes in civic problems and possible solutions.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2015>4>a", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "List five effects of human trafficking.", "images": [], "marking_scheme": "i. Brain drain  ii. Bad Image to the country and its citizen  iii. Illegal migration  iv. Untimely death  v. Unwanted pregnancy  vi. Social stigmatisation", "marks": "10", "difficulty": "1"}, {"id": "theory>Civic Education>2015>4>b>i", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "What does WOTCLEF stands for?", "images": [], "marking_scheme": "Women Trafficking and Child Labour Eradication Foundation", "marks": "2", "difficulty": "1"}, {"id": "theory>Civic Education>2015>4>b>ii", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "Identify three activities of WOTFCLEF aimed at curbing human trafficking in Nigeria.", "images": [], "marking_scheme": "i. Conducting research and dissiminating results on best practices for addressing human trafficking  ii.  Developing training materials on best practices for tackling human trafficking  iii. Providing counselling services to victims  iv. Education support for victims  v. Assistance to victims  vi. Establishment of rehabilitation centres.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2015>5>a", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : MEANING OF DRUG ABUSE", "question": "What is drug trafficking?", "images": [], "marking_scheme": "Drug trafficking is a world-wide illegal trade involving the cultivation, manufacture, distribution and sale of substances/drugs, which are identified under the drug prohibition laws.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2015>5>b", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : CONSEQUENCES OF DRUG ABUSE", "question": "State four social consequences of drug abuse.", "images": [], "marking_scheme": "i. Disruption of societal peace and transquility as a result of drug-related crimes and conflicts among drug trafficker/barons.  ii. Negative effects on younger generation as addicts become perverse role models   iii. Preventable road accidents caused by drugs addicts.  iv. Arson become widespread  v. Armed robbery becomes widespread.  vi. Rampant cases of rape in the society  vii. Murder cases become rampant in the society  viii. Widespread of violence in the society", "marks": "12", "difficulty": "1"}, {"id": "theory>Civic Education>2015>6>a", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : REASONS FOR CULTISM", "question": "Explain three reasons students join cults.", "images": [], "marking_scheme": "- Academic success  - Social identity  - Sense of security  - Hardship/Lack of parental care  - Family background  - Popularity  - False impression  - Position seeking", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2015>6>b", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "State three government policies on cultism.", "images": [], "marking_scheme": "- Government enhanced security presence in schools and colleges  - Introduction of civic education to educate citizens in social vices and other immoral behaviour associated with cultism in schools  - Public renunciation of membership of secret societies should be encouraged by government  - Public enlightenment campaign against cultism  - Prosecution and sentencing to jail terms, those found guilty of any students found to be members of secret cult from campus  - Newly admitted students are made to take oath not to belong to any secret cult  - Enacting enabling laws proscribing cultism.", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2015>7", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY", "question": "Highlight five roles civil society can play in promoting popular participation.", "images": [], "marking_scheme": "- Educate people about their rights, duties and obligations  - Help government in alleviating poverty by creating jobs or promoting youth empowerment  - Promote democracy by monitoring elections  - Strengthen harmonious relations in a multi-ethnic society  - Inform the public on important national issues   - Make demand for social justice  - Pursue the enforcement of fundamental human rights  - Mobilize citizens for popular participation in politics  - Check the excesses of political leaders and state officials.", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2015>8", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Describe five ways through which the Nigerian society can benefit from citizen's active participation in the political process.", "images": [], "marking_scheme": "- Conducive environmen for business/investment: Active participation of the people in government creates environment conducive for business & other investment activities.  - Accountability, transparency, due process and probity: Active participation of citizens in the political process, ensures accountability, transparency, due process and probity in governance  - Peace and Harmony: when citizens actively participate in the political process, they will enjoy peace and harmony without much agitation.  - Peaceful order of Succession: Peaceful transition is ensured from one regime to another in a society where peace and order pervade.  - Credible elections: When citizens actively participate in the electoral/political process, it will confer credibility on the process  - Political Awareness: when citizens participate in the political process, they will become politically conscious, enjoy their rights and perform corresponding duties and obligations to the society.  - Responsible and Responsive Government: The society will elect or get a government that is receptive to the people's concerns, needs and aspirations.  - Political stability: This ensures law and order for economic and political development in the society.  - National Development: There will be rapid socio-economic development if citizens participate in the electoral process", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2015>9>a", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING OF NATIONAL DEVELOPMENT", "question": "Define national development.", "images": [], "marking_scheme": "National development is the process by which a country improves the social and economic well-being of its citizens through the provision of amenities such as quality education, good roads, medical facilities and other social amenities.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2015>9>b", "subject": "Civic Education", "year": "2015", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "Explain four ways in which corruption has retarded the development of the Nigeria.", "images": [], "marking_scheme": "- Nepotism/favouritism becomes the norm in the society. This retards productivity.  - Preversion of values/moral decadence in which the upright begin to doubt themselves.  - Political Instability which can lead to military coup and under development.  - Power struggles which lead to the neglect of core duties and loss of lives.  - It reduces the lifespan of citizens as mortality.  - It deepens the poverty level.  - It wipes out jobs.", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2016>1>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "State four significance effects of lack of contentment on the society.", "images": [], "marking_scheme": "- It reduces conflicts among individuals and groups in the society.  - It eliminates envy and jealousy in the society.  - It leads to self-reliance and respect for others.  - It endangers peace and development in the society.  - It discourages corrupt practices.  - It discourages embezzlement.  - It promotes dignity of labour orientation.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2016>1>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Mention three negative effects of lack of contentment on the society.", "images": [], "marking_scheme": "- It leads to false living   - It leads to conflicts  - It promotes crimes  - It result in jealousy/dishonesty  - It leads to greed   - It breeds corrupt practices.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2016>2", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "Explain five nationalistic roles expected of individuals in the society.", "images": [], "marking_scheme": "- Exemplary representation of one's society/country  - Regular payment of taxes when applicable  - Rendering services for national security even at the expense of one's life  - Engaging in constructive criticism of leaders and government policies  - Opposing the implementation of policies and programmes that do not have human face  - Placing National Interest above personal Interest  - Encouraging justice, equity in the society  - Encouraging popular participation  - Providing solutions to prevailing societal problems   - Drawing the attention of government and other leaders to pressing needs and problems of society.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2016>3>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF NATIONALISM", "question": "Define national consciousness.", "images": [], "marking_scheme": "National Consciousness: it is the feeling of attachment to one's country over and above every other considerations, interests or pecularities for the promotion of her common welfare or development.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2016>3>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : WAYS OF PROMOTING NATIONAL CONSCIOUSNESS, INTEGRITY AND UNITY IN THE SOCIETY", "question": "State four ways of promoting national consciousness.", "images": [], "marking_scheme": "- Demonstrating tolerance of opposition  - Team work or cooperation in national issues  - Recognising and rewarding excellent performance/services  - Sing National Anthem  - Respecting National symbols  - Emulating exemplary leadership qualities  - Participating in community development", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2016>4>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "Define Youth empowerment.", "images": [], "marking_scheme": "Youth empowerment is a development programme aimed at creating opportunities that will encourage and develop the youths to be morally responsible, self-reliant and financially productive citizens.", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2016>4>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "List three youth empowerment.skills.", "images": [], "marking_scheme": "- Negotiation skills  - Manipulative skills  - Human relation skills  - Artistic skills  - Vocational skills  - Communicative skills  - Decision making skills  - Leadership skills  - Self-actualization skills", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2016>4>c", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "State three efforts of government towards youth empowerment.", "images": [], "marking_scheme": "- Collaboration of government with non-governmental organisation  - Provision of incentives to make agricultural attractive to the youths  - Provision of soft loan for youths for the establishment of small scale and medium scale enterprises  - Awakening initiatives on youth empowerment through seminars, workshops etc.  - Establishment of different agencies, ministries and parastatals for youth empowerment.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2016>5>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "State four preventive measures for HIV/AIDS.", "images": [], "marking_scheme": "- Establishment of drug substitution therapy programmes   - Establishment and operation of drug treatment facilities  - Promotion of voluntary counselling and testing centre to know one's status  - Encourage protective sex through the use of condom  - Avoiding contact with infected body fluid such as blood  - Destruction of used needles, syringes and other tools", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2016>5>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : SYMPTOMS AND EFFECTS OF HIV/AIDS", "question": "Mention hree ways by which HIV/AIDS can be managed.", "images": [], "marking_scheme": "- Subsidizing the cost of treatment of people with HIV/AIDS  - Discouraging stigmatization of people living with HIV/AIDS  - Engaging in productive exercises  - Stay positive about survival  - Eating balanced diet  - Taking the recommended Anti-Retroviral therapy drugs as at when due  - Teaching of sex/HIV/AIDS education in schools.", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2016>6>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "State two functions of the National Drug Law Enforcement Agency (NDLEA).", "images": [], "marking_scheme": "- It provides measures that will ensure the elimination and prevention of the root cause of the problem of narcotic drug.  - It promote effective enforcement of law to suppress illicit trafficking in narcotics drugs.  - It adopts meaures to increase the effectiveness hard drug trafficking eradication efforts.  - It investigates people suspected to have dealings with hard drugs and enforces laws against the cultivation, sales and use of hard drugs.  - It adopts measures to eradicate illicit cultivation of narcotic drugs.  - It coordinates all drugs laws and enforcement function.", "marks": "7.5", "difficulty": "1"}, {"id": "theory>Civic Education>2016>6>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "Outline three functions of the National Agency for Food and Drug Administration and Control (NAFDAC).", "images": [], "marking_scheme": "- It engages in the investigation of raw materials for foods, drugs, cosmetics etc.  - It registers foods, drugs, medical services, packaged water and chemicals.  - It certifies production site of foods and drugs - related products.  - It conducts inspections on imported foods, drugs, cosmetics so as to ensure quality.  - It regulates and controls the importation and exportation of drugs.", "marks": "7.5", "difficulty": "1"}, {"id": "theory>Civic Education>2016>7>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "List three features of the 1999 Constitution of Nigeria.", "images": [], "marking_scheme": "- It identifies the state and the people for which the constitution was made (i.e Nigeria and Nigerians)  - It provides for 36 states and 774 local government in Nigeria and the procedure for creating new ones.  - It provides for unicameral legislature at the states & local government levels.  - It has a bicameral legislature at the federal level.  - It has rigid procedure for amendments.  - It is a federal constitution.  - The constitution is written in a single documents", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2016>7>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Highlight four significant of the 1999 Constitution of Nigeria.", "images": [], "marking_scheme": "- It provides room for separation of powers and checks and balances  - It protects rights of individuals and groups in the country  - It spells out the modalities for change of government  - It provides for legitimacy of government at all levels  - It guarantees the rights and survival of the minority.  - The constitution promotes the oneness and unity of the country.", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2016>8>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : MEANING, TYPES, AND FEATURES OF DEMOCRACY;", "question": "Define Representative Democracy.", "images": [], "marking_scheme": "Representative Democracy is a form of goverment whereby eligible citizens elect their leaders through periodic elections to present them at all levels of government for a fixed tenure.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2016>8>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "State three reasons Nigeria adopts representative democracy.", "images": [], "marking_scheme": "- Desire to protect the interest of minorities.  - Complexity of many political issues.  - Greater political participation.  - Large territorial size of the country  - Complex state structure of Nigerian government  - Large electoral size due to high population.", "marks": "6", "difficulty": "2"}, {"id": "theory>Civic Education>2016>8>c", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF DEMOCRACY", "question": "List three factors that retard the growth of democracy in Nigeria.", "images": [], "marking_scheme": "- Elections based on sentiments  - Bribery and corruption  - High cost of running democracy  - High level of illiteracy/ignorance  - Lack of proper political education  - Electoral malpractice.", "marks": "6", "difficulty": "2"}, {"id": "theory>Civic Education>2016>9>a", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : IMPORTANCE OF PUBLIC SERVICE", "question": "State four importance of public service in Nigeria.", "images": [], "marking_scheme": "- It collects revenue for government  - It acts as governmental agent to the general public   - It provides essential services at cheaper rates  - It performs delegated functions  - It creates employment opportunities  - It advises the government  - It implements government policies   - It advices in the formulation of the policies of government.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2016>9>b", "subject": "Civic Education", "year": "2016", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : WAYS OF IMPROVING THE PUBLIC SERVICE", "question": "List three ways by which public service can be improved in the country.", "images": [], "marking_scheme": "- Political education  - Job security  - Freedom of Information  - Press control  - Training and re-training  - Incentive for meeting set goals  - Effective legislative oversight function  - Enhancement of due process mechanism  - Depoliticization of public service.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2017>1>a", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-PERSONAL RELATIONSHIPS", "question": "Define Interpersonal relationship.", "images": [], "marking_scheme": "Interpersonal relationship is a process of interaction between two or more people in society for the promotion of peaceful co-existence.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2017>1>b", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS THAT PROMOTE INTERPERSONAL RELATIONSHIPS", "question": "State four ways acts of kindness can promote interpersonal relationships.", "images": [], "marking_scheme": "i. Overlooking and forgiving misdeed of others.  ii. Showing kindness to others.  iii. Being accommodating.  iv. Being selfless.  v. Showing empathy and compassion towards each others.  vi. Willingness to assist each others.  vii. Giving deserved attention to each others.  viii. Entering that no partner feels superior to others.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2017>2>a", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : MEANING OF TRAFFIC REGULATIONS", "question": "Define traffic regulations.", "images": [], "marking_scheme": "Traffic regulations is a set of rules, guidelines and principles that direct and control vehicular traffic and other road users for effective road use and avoidance of accidents.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2017>2>b", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Outline six reasons why inspection of vehicle documents is necessary in Nigeria.", "images": [], "marking_scheme": "i. To ensure the use of standard vehicle parts.  ii. To ensure regular maintenance of vehicles.  iii. To ensure payments of approved dues by road users.  iv. To ascertain and ensure sanity of road users.  v. To ascertain proof of ownership of vehicle(s).  vi. To ensure safety of lives and properties.  vii. To ascertain the road worthiness of vehicles.  viii. To have a better information about holders of drivers permit.  ix. To discourage vehicle theft", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2017>3>a", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : MEANING OF RESPONSIBLE PARENTHOOD", "question": "Define responsible parenthood.", "images": [], "marking_scheme": "Responsible parenthood is the act or process of effective discharge of duties and obligations of upbringing of children/wards by parents.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2017>3>b", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "Explain four importance of responsible parenthood to national development.", "images": [], "marking_scheme": "i. It trains children to uphold law and order.  ii. It trains children to be peace loving.  iii. It trains children to be patriotic.  iv. It trains children to know their rights.  v. It trains children to abhor criminal act in society.  vi. It nurtures children to know and perform their duties.  vii. It breeds children with good leadership qualities.  viii. It breeds Godfearing children.  ix. It trains children to abhor social vices/problems.  x. It trains children to be exemplary/role model to others.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2017>4", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "Outline any five functions of the National Agency for the prohibition of traffic in Persons and other Related Matters (NAPTIP).", "images": [], "marking_scheme": "- To adopt measures that will increase the effectiveness of eradication of trafficking in persons.  - To establish proper communication channels, conduct research and work on improving International cooperation in the suppression of traffic in persons.  - To reinforce and supplement measures in bilateral and multilateral treaties and conventions on traffic in persons.  - To work in collaboration with other agencies or bodies that may ensure elimination of traffic in persons.  - To strengthen and enhance effective legal means for international co-operation in suppressing the International activities of traffic in persons.  - To investigate and prosecute traffickers.  - To coordinate all laws on trafficking in persons.  - To enhance effectiveness of law enforcement agents in suppressing traffic in persons.", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2017>5>a", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "State three reasons why high incidence of cultism constitutes a national problem.", "images": [], "marking_scheme": "- It leads to loss of lives and properties.  - It leads to value disorientation.  - It erodes commitment to excellence.  - It allows the socio-economic and political structures to be manned by irresponsible citizens.  - It brings about the breakdown of law and order.  - It promotes mediocrity in the national labour force.  - It discourages investment/development in society.  - It increases crime rates in society.  - It breeds irresponsible citizens.  - It gives bad images to the society.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2017>5>b", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "List five reasons why eradication of cultism in schools will promote national development.", "images": [], "marking_scheme": "- It promotes peace and order in society.  - It attracts investment/development projects.  - It enhances national pride.  - It enhances economic properties.  - It promotes commitment to excellence.  - It ensures security of lives and properties  - It will promotes commitment to national development.  - It will promote the production of experts.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2017>5>c", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS", "question": "Highlight two factors hindering the eradication of cultism in Nigerian schools.", "images": [], "marking_scheme": "i. Intimidation of school authorities by cultists.  ii. Non-implementation of punishments designed for cultists.  iii. Admission of expelled students due to cult activities into other school/colleges.  iv. Involvement of teachers in cult activities.  v. Involvement of children of influential parents.  vi. Ignorance on the part of students.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2017>6", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Explain five ways Civic Education can help eradicate drug addiction among youths.", "images": [], "marking_scheme": "i. Through knowledge acquisition on safe use of drugs.  ii. By encouraging youths to appreciate the essence of good health.  iii. By teaching youths necessary skills for self-control.  iv. By teaching youths to appreciate themselves as future leaders/parents in society.  v. By discouraging youths from associating with drugs addicted group/peers.  vi. By discouraging youths from illegal use of drugs.  vii. Encouraging youths to be good citizens.  viii. Awareness creation about the danger of drug addiction.  ix. Through skill acquisition for youths empowerment", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2017>7>a", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain CONSTITUTION as a pillar of democracy", "images": [], "marking_scheme": "Constitution: It is the fundamental laws, rules, regulations and other related elements according to which democratic states are expected to be governed.", "marks": "3", "difficulty": "3"}, {"id": "theory>Civic Education>2017>7>b", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain ARMS OF GOVERNMENT as a pillar of democracy", "images": [], "marking_scheme": "Arms of Government: These are the totality of administrative bodies/organs which make, implement and adjudicate laws for the operation of government in a democratic state e.g Legislative, Executive and Judiciary.", "marks": "3", "difficulty": "3"}, {"id": "theory>Civic Education>2017>7>c", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain POLITICAL PARTIES as a pillar of democracy", "images": [], "marking_scheme": "Political Parties: These are organised groups of people who share common ideas with sole aim of contesting elections to gain political power in a democratic state.", "marks": "2", "difficulty": "3"}, {"id": "theory>Civic Education>2017>7>d", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "d", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain FREE PRESS as a pillar of democracy", "images": [], "marking_scheme": "Free Press: This refers to a situation or condition in which media organisations are allowed to performed their functions of informing, educating, entertaining people and scrutinizing government activities without undue censorship for the purpose of good government in a democracy.", "marks": "2", "difficulty": "3"}, {"id": "theory>Civic Education>2017>7>e", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "e", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain ARMED FORCES as a pillar of democracy", "images": [], "marking_scheme": "Armed Forces: These are constitutionally established bodies empowered to protect/defend. The territorial integrity of a democratic state against internal insurrection and external aggression.", "marks": "2", "difficulty": "3"}, {"id": "theory>Civic Education>2017>7>f", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "f", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain CIVIL SOCIETIES as a pillar of democracy", "images": [], "marking_scheme": "Civil Societies: These are private non-profit organisations formed to promote collectively shared values, interests and objectives that are capable of enhancing the general welfare and development of democratic states.", "marks": "2", "difficulty": "3"}, {"id": "theory>Civic Education>2017>8>a", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : IMPORTANCE OF PUBLIC SERVICE", "question": "State three reasons why public service is important for the effective function of government.", "images": [], "marking_scheme": "i. Implements policies and programmes of government.  ii. Advices the political heads of government institutions.  iii. Keeps records of government properties and transactions.  iv. Collects and supply vital information.  v. Assists the government to mobilize funds.  vi. Assists in information of policies of government.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2017>8>b", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "Identify three ways by which Public/Civic service Commission contributes to the effective operation of public service in Nigeria.", "images": [], "marking_scheme": "- Investigation of unfair treatment of public servants.  - Training of public servants to enhance performance.  - Promotion of public servants  - Discipline of erring public servants  - Posting/deployment of public servants  - Recruitment of official into positions in public services.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2017>9", "subject": "Civic Education", "year": "2017", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Highlight five relevance of power sharing among the three tiers of government in Nigeria.", "images": [], "marking_scheme": "- It generates greater employment opportunities for the citizens.  - It encourages different units of government to develop at their own price.  - It ensures peace and harmony in society.  - It promotes rapid socio-economic and political development.  - It promotes active participation on governance.  - It promotes focus on national interests.  - It promotes adherence to the rule of law.  - The stability of government is guaranteed.  - People's rights as citizens of a place are secured.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2018>1>a", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "Define Orderliness.", "images": [], "marking_scheme": "Orderliness is defined as the act of doing things in the right and acceptable way in conformitywith the rules and regulations of the society.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2018>1>b", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "State six ways of exhibiting orderliness in the society.", "images": [], "marking_scheme": "- Obeying traffic regulations.  - Tolerance.  - Peaceful co-existence.  - Following due process.  - Joining queues  - Orderly conduct in public places.  - Obedience to constituted authorities.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2018>2", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "2", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : SKILLS FOR RESOLVING INTER-COMMUNAL CONFLICTS", "question": "Highlight five skills for resolving inter-communal conflicts.", "images": [], "marking_scheme": "- Tolerance  - Litigation  - Negotiation  - Co-operation  - Compromise  - Mutual respect  - Compensation  - Dialogue  - Reconciliation", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2018>3>a", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY", "question": "What is constituted authority?", "images": [], "marking_scheme": "Constituted authority refers to an individual, group in body vested with legitimate power to carry out specific duties for the common good of a society.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2018>3>b", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY", "question": "Highlight six advantages of constituted authority.", "images": [], "marking_scheme": "- It provides social amenities to the people.  - It provides employment to the people.  - It ensures protection of human rights.  - It ensures stability and continuity in the society.  - It contributes to the smooth running of the society.  - It assists in enforcing the rules and ensuring compliance by members.  - It assists in formulating policies and making decisions.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2018>4>a", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : DRUGS THAT CAN BE ABUSED", "question": "Mention three drugs that can be abused.", "images": [], "marking_scheme": "- Codeine  - Cannabis  - Heroin  - Alcohol  - Cocaine  - Marijuana Hemp", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2018>4>b", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "List six visible behaviours of drug addicts.", "images": [], "marking_scheme": "- Truancy  - Depression  - Poor performance in academics  - Withdrawal from school  - Severe Headache  - Violence  - Nuisance  - Nervousness  - Moodiness", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2018>4>c", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : CONSEQUENCES OF DRUG ABUSE", "question": "State two social consequences of drug abuse.", "images": [], "marking_scheme": "- Death  - Isolation  - Stigmatization  - Nuisance  - Domestic violence  - Homelessness", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2018>5>a", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "Identify three ways People Living with HIV/AIDS (PLWHA) are discriminated against.", "images": [], "marking_scheme": "- Non-recognition of HIV/AIDS victims in the society.  - Loss of income and other means of livelihood.  - By being ostractized by friends and family members  - Loss of employment  - Denial of their fundamental human rights  - Denial of employment  - Back biting  - Confinement", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2018>5>b", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "Explain three reasons why stigmatization of People Living with HIV/AIDS (PLWHA) should be discouraged.", "images": [], "marking_scheme": "- To discourage the idea of brain drain.  - They can be used as volunteers for HIV/AIDS prevention campaign in society.  - To curb the rate of suicide attempts in the society.  - Discrimination should be discouraged due to the fact that anyone can find him/herself in the condition.  - They need help and care  - To encourage the general public to ascertain their HIV/AIDS status.", "marks": "7.5", "difficulty": "3"}, {"id": "theory>Civic Education>2018>6>a", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "Highlight three ways by which Nigerian youths are being empowered.", "images": [], "marking_scheme": "- Skill acquisition  - Focused employment of youths in government parastatals  - Introduction of entrepreneurial courses in schools  - Accessing soft loan, grants etc.  - Enlightenment programmes  - Participation in compulsory youth service schemes e.g NYSC.", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2018>6>b", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : IMPORTANCE AND BENEFITS OF YOUTH EMPOWERMENT SKILLS", "question": "State three social consequence of high rate of youth unemployment in Nigeria.", "images": [], "marking_scheme": "i. Over dependency on parents  ii. Laziness/idleness  iii. Loss of self pride  iv. Loss of confidence  v. Engagement in crime  vi. Unemployment encouraged deviant tendencies", "marks": "7.5", "difficulty": "3"}, {"id": "theory>Civic Education>2018>7>a", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "In what five ways can citizens demonstrate political apathy?", "images": [], "marking_scheme": "- In difference to government activities.  - Unwillingness to attend political party activities.  - Refusal to vote during elections.  - Refusal of eligible voters to register for voting.  - Refusal to check their names in the voter's register", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2018>7>b", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CAUSES OF POLITICAL APATHY", "question": "Give five reasons for political apathy.", "images": [], "marking_scheme": "- Ignorance  - Religious beliefs  - Lack of transparency  - Negative campaign by parties and politicians  - Bad governance  - Failure to fulfill electoral promises  - Fear of violence  - Inadequate security before, during and after elections.", "marks": "10", "difficulty": "2"}, {"id": "theory>Civic Education>2018>8", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY", "question": "State five ways illiteracy can be a challenge to popular participation in a democracy.", "images": [], "marking_scheme": "- Preventing some citizens from contesting elections  - Making voters to be vulnerable to negative forms of political participation  - Development of a sense of Inferiority Complex  - Wrong perception of democratic political process  - Negative attitude towards democratic political process  - Ignorance about democratic political process  - Inability of illiterate citizens to read and write  - Illiteracy can be a challenge to political participation in a democracy", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2018>9", "subject": "Civic Education", "year": "2018", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "Explain five reasons why accountability should be the watchword of public servants in Nigeria.", "images": [], "marking_scheme": "- To promote accountability  - To build confidence in foreign investors  - To enable the governed have an idea of what is expected from government  - To ensure security of government policies  - To help check corrupt practices   - For maintenance of confidence  - For sustainability of the structure of governments", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2019>1>a", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW", "question": "Define the term Justice", "images": [], "marking_scheme": "Justice is a state of being fair, equitable, impartial, neutral and unbiased in treating or handling issues, matters involving individuals or groups in society.", "marks": "6", "difficulty": "1"}, {"id": "theory>Civic Education>2019>1>b>i", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS", "question": "Explain what the scale stands for.", "images": [], "marking_scheme": "The Scale: The scale stands for weighing the claims and evidence presented by parties in dispute to ensure balance and fairness in order to arrives at final ruling or judgement.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2019>1>b>ii", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS", "question": "Explain what the sword stands for.", "images": [], "marking_scheme": "The Sword: The sword symbolizes the readiness to dispense and enforce justice. The double-edged nature of the sword signifies that justice can be either way once the evidence and claims are substantiated and established.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2019>1>b>iii", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : DIFFERENT CULT GROUPS IN NIGERIA AND THEIR SYMBOLS", "question": "Explain what the blindfold stands for.", "images": [], "marking_scheme": "The blindfold: The blindfold represents objectivity in meeting out justice without, fear or favour, regardless of wealth, political affiliation, popularity.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2019>2>a", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "State three significance of nationalism to political development in Nigeria.", "images": [], "marking_scheme": "- It promoted national self-reliance  - It led to the establishment of higher institutions  - It created awareness of fundamental human right  - It created a sense of allegiance to nation and patriotism  - It led to major constitutional development  - It helped in creation of political awareness  - It led to formation of political parties  - It led to establishment of the media  - It promoted good and responsible governance", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2019>2>b", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : THE NATIONALISTIC ROLES OF INDIVIDUALS AND GROUPS", "question": "Highlight three Nationlaistic roles of Kwame Nkrumah.", "images": [], "marking_scheme": "- He led Ghana to gain Independence from the british  - His government carried out massive infrastructural development in Ghana  - He mobilized Ghananians to oppose oppressive colonial policies  - He established Newspaper in pre-independence Ghana to promote nationalist activities  - He encouraged the formation of nationalistic group in Ghana  - His government initiated and pursued African-centered foreign policy.  - He participated activity in pre-independence constitutional conferences.", "marks": "7.5", "difficulty": "2"}, {"id": "theory>Civic Education>2019>3", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "3", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Explain five roles of federal road safety corps (FRSC) in curbing road accidents in Nigeria.", "images": [], "marking_scheme": "- Disciplining and penalizing erring drivers  - Issuing drivers license  - Regulating the use of sirens  - Educating road users  - Determining speed limits for all road users  - Conducting researches into ways of improving the safety of road users  - Checking vehicle particulars and drivers' license   - Clearing obstruction on the highways  - Standardizing highway traffic codes.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2019>4", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "State five behaviours Associated with Drug Addiction.", "images": [], "marking_scheme": "- Indulgence in occasional reckless spending  - They take risks that are dangerous to them self  - They are desperate for money to buy drugs  - Lack of sleep (Insomnia)  - They are easily agitated aggressive and violent  - Loss of appetite  - They always look sad, moody and depressed when the effects of drugs have waned.  - Lying and other unethical behaviour  - They neglect obligation at work  - Lack of concentration and drop-out of school.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2019>5", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "State five Hardships that victims of human trafficking may experience in the hands of human traffickers.", "images": [], "marking_scheme": "- Untimely death of victims due to ill health and maltreatment.  - Unwanted pregnancy and forced abortion among female victims.  - Most victims of human trafficking end up in abject poverty due to exploitation.  - Emotional mental and physical abuse of victims.  - Victims of human trafficking suffer stigmatization or bad image in the society.  - Victims are denied access to education especially children.  - Risk of contracting sexually transmitted diseases such HIV/AIDS, e.t.c.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2019>6>a>i", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS", "question": "Explain the term HIV", "images": [], "marking_scheme": "HIV: This means human immune deficiency virus. It is a type of virus that is transmitted through bodily fluids which attacks, weakens and destroys the white blood cells and make the infected person develop AIDS.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2019>6>a>ii", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : MEANING OF HIV/AIDS", "question": "Explain the term AIDS.", "images": [], "marking_scheme": "AIDS: This means Acquired Immune Deficiency Syndrome. It refers to a condition in which a HIV positive person become Immune-deficient as a result of the destruction of Immune system which makes the victims vulnerable to opportunistic infections.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2019>6>b", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : SYMPTOMS AND EFFECTS OF HIV/AIDS", "question": "List nine Symptoms of AIDS.", "images": [], "marking_scheme": "- Weight loss and emaciation  - Excessive sweating  - Nausea and vomitting  - Chills  - Premonia  - Shortness of breath  - Loss of appetite  - Frequent diarrhea and dehydration  - Anaemia and pale  - Chronic fatique, depression and weakness.", "marks": "9", "difficulty": "2"}, {"id": "theory>Civic Education>2019>7>a", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : FEATURES OF RULE OF LAW", "question": "List the three main feature of the rule of law.", "images": [], "marking_scheme": "- Equality before law  - Supremacy of the law  - Respect for fundamental human right", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2019>7>b", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF RULE OF LAW", "question": "State four Hindrances to the applications of the rule of law in the society.", "images": [], "marking_scheme": "- Disobedience to court order  - Illiteracy/ignorance  - Nepotism or favouritism  - Declaration of state of emergency  - Custom and tradition  - Law with retrospective effect  - War  - Use of special courts for some cases  - Delayed justice  - Delegated legislation  - Lack of judicial independence", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2019>8>a", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : MEANING OF POLITICAL APATHY", "question": "What is Political Apathy?", "images": [], "marking_scheme": "Political apathy can simply be defined as the loss of interest and manifestation of withdraw from politics and political activities by citizens of a country.", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2019>8>b", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "State two dangers of political apathy to the society.", "images": [], "marking_scheme": "- Emergence of undemocratic government  - It create opportunity for manipulation of electoral process  - Breeding of corruption in government and abuse of power  - Decline in civil duties  - Denial of citizens rights  - Insufficient knowledge of political activities", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2019>8>c", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : WAYS OF DISCOURAGING POLITICAL APATHY", "question": "Highlight four ways of addressing political apathy.", "images": [], "marking_scheme": "- Encouraging an Independent and corrupt free body.  - Strengthening civil society and other relevance organisation.  - Conducting free and fair and credible elections.  - Simplification of electoral process.  - Joining and forming political organisation.  - Independent judiciary.", "marks": "5", "difficulty": "3"}, {"id": "theory>Civic Education>2019>9>a", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Define Civic Society.", "images": [], "marking_scheme": "Civil society can be defined as non-governmental organisation formed for the purposes of promoting and protecting the interest generality of the people as small as mobilizing them in participation in the governance and development of the society.", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2019>9>b", "subject": "Civic Education", "year": "2019", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC", "question": "Outline six Impediments to the effectiveness of civil societies in Nigeria.", "images": [], "marking_scheme": "- Overdependence on external sources for funding and operational support.  - Types of government in power.  - Lack of accountability.  - Inadequate funding.  - Political instability.  - Lack of self-evaluation and criticism.  - Preferential treatment in their operation.  - Corruption on the part of member.  - They are often rigid in their views of public interest.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2020>1>a", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP EDUCATION", "question": "Define citizenship education.", "images": [], "marking_scheme": "Citizenship education is education that provides the background knowledge necessary to create an ongoing stream of new citizens participating and engaging with the creation of a civilized society.", "marks": "8", "difficulty": "1"}, {"id": "theory>Civic Education>2020>1>b", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "Highlight four relevance of citizenship education to the sustenance of the Nigeria society", "images": [], "marking_scheme": "-  Self confidence: It helps the young people to develop self-confidence and a sense of agency, and sucessfully deal with life changes and challenges such as bullying and discrimination.  -  Responsibilities: It enables the young people to make a positive contribution by developing the knowledge and experience needed to claim their rights and understand their responsibilies.  -  Democratic process: It helps the society to create an active and responsible citizenry,willing to participate in the life of the nation and the wider world and play its part in  the democratic process.  -  Support of democracy: It supports a democracy in which people participate and belong.", "marks": "7", "difficulty": "2"}, {"id": "theory>Civic Education>2020>2>a", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "List five qualities an ideal parent is expected to possess", "images": [], "marking_scheme": "- Patience  - Understanding  - Ability to express love  - Listening  - Empathy", "marks": "7", "difficulty": "2"}, {"id": "theory>Civic Education>2020>2>b", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "State five ways good parenting acts as an incubator for responsible citizens in Nigeria", "images": [], "marking_scheme": "- Teach compassion, empathy, and other similar values through role play.  - Do not be afraid to discipline them firmly  - Assign them age-appropriate tasks to teach responsibility  - Be their role model  - Support them in their endeavors", "marks": "8", "difficulty": "2"}, {"id": "theory>Civic Education>2020>3>a", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS", "question": "Define inter-communal relationship", "images": [], "marking_scheme": "Inter-communal relationship is a relationship which exist between two or more communities.It simply means existing between communities i.e the way one community behaves towards another.", "marks": "7", "difficulty": "1"}, {"id": "theory>Civic Education>2020>3>b", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "Explain four ways by which inter-communal relationship promotes community development in Nigeria", "images": [], "marking_scheme": "- Promotion of peace and unity: A positive inter-communal relationship will help to promote peace and unity in the environment.It will help to unite community members towards the development of the community.  - Enhancement of security: It ensures stable and standly security consciousness in  the communities.It will help to remove the fear of violence, war or any kind of between communities  - Promotion of political development: A good and positive inter-communal relationship helps to promote political development of different kinds and ensure that concerned communities participate in issues related to the development of the community.  - Promotion of economic progress: A responsible and positive inter-communal relationship will enhance peaceful atmosphere and strategies for each other or each other business like inter-marketing strategies etc.", "marks": "8", "difficulty": "2"}, {"id": "theory>Civic Education>2020>4", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "4", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Outline five ways of curbing cultism in the Nigeria School System", "images": [], "marking_scheme": "- The fear of God is begining of wisdom: Efforts should be made at home,peers and the entire community to inculate the fear of God into youths  - Parents should endeavour to observe and know the person or friends their children moves with  - Visitation of parents to school to be aware about the activities of their children  - Good school allows for proper monitoring of students i.e counselling in the school and at homee  - Good teacher/student relationship", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2020>5", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "5", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "State five contibutions of individuals at stopping human trafficking", "images": [], "marking_scheme": "- Organize a fundraiser and donate the proceeds to an anti-trafficking organization will help the stop of trafficking  - Encourage your local schools or school district to include human trafficking in their curricula and to develop protocols for identifying and reporting a suspected case of human trafficking or responding to a potential victim  - Use your social media platforms to raise awareness about human trafficking,and in term of exposing them.  - Become a mentor to a young person or someone in need.In other words be well-informed.Set up a web alert to receive current human trafficking news.  - Volunteer and support anti-trafficking efforts in your community to eradicate any form of trafficking.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2020>6", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "6", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "Highlight five ways of supporting people living with HIV/AIDS (PLWHA)", "images": [], "marking_scheme": "-  Support:  Showing love,respect and support  -  Open minded: Knowing the facts about HIV/AIDS and talking openly about the disease  -  Reduction of stress: Helping to reduce stress and stressful situations  -  Providing food: Helping to provide balanced nutritious meals  - Treatment: Encouraging them to get treatment if they are sick.Most infections are easily treated and cured,even if a person is HIV positive", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2020>7>a", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain the term pillars of democracy", "images": [], "marking_scheme": "The pillars of democracy refers to the intellectual foundations that support the philosophy of democracy.With knowledge of the pillars then a person can predict additional features that should be used in a practical application of the theory of democracy.", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2020>7>b", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Describe the Armed Forces of Nigeria as a pillar of democracy", "images": [], "marking_scheme": "The Nigerian armed forces have been engaged actively in the process of governance from way back.The military in Nigeria have become a destabilizing factor in the sustenance of democracy.The Nigerian military is not only highly politicized but polarized along religious and ethnic lines as result of their involvement in politics and administration of governance. Nigeria military have executed six successful coups and a similar number of failed ones.All these military adventures into politics have continued to undermine the growth and development of democracy in Nigeria,The armed forces are one of the critical institutions that must be strengthened and educated to understand their roles and their importance as a back bone of democracy.The military must be well trained and professionalized to know that thier duty is to protect the nation against extrenal aggression,They must not be used as tools of internal oppression and rigging elections by the ruling party or an instrument of instability through coup plotting by ambitious officers and their civilian sponsor.", "marks": "5", "difficulty": "3"}, {"id": "theory>Civic Education>2020>7>c", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF DEMOCRACY", "question": "State three significance of free press to the sustenance of democratic governance", "images": [], "marking_scheme": "- A free press plays a vital role in democratic societies,enabling the open exchange of information and opinions among ordinary citizens,businesses,citizen associations,political parties, and governments.    - The media directly contributes to democratisation and governance by serving as watch dog( promoting accountability and transparency), a civil forum(allowing multiple voices to be heard) and agenda-setter(highlighting social problems)    - Political freedoms and free press contribute indirectly to human development by encouraging government responsiveness to public concerns.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2020>8", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "8", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : POLITICAL APATHY : CONSEQUENCES OF POLITICAL APATHY", "question": "Outline five consequences of political apathy to a developing nation", "images": [], "marking_scheme": "- Political Apathy threatens democratic dispensation: When a politician wins an election in a high voter apathy political election,such a winner wins with a minority vote.Such a vote doesn't give the winner confidence that he is a popular political representative in a given area.  - Elections are not representative: Results of elections are supposed to be based on majority feelings.With political apathy,such is difficult.  - Political Apathy hinders good governance and decision making: When elected political leaders win with a minority vote,such leaders feel reluctant to mobilise majority citizens in the area who might not have vote for him or her  - Political Apathy retards community and national development processes.Instead of a political leader to concentrate on spending more time facilitating development related projects,he or she might spend more time justisfying that he or she is current ward councilor,member of parliament or a current president.  - Another major cause of high voter apathy is that most politicians don't perform to the expectations of the electorate", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2020>9>a", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : QUALITIES/CHARACTERISTICS OF CIVIL SOCIETY; I.E. ACCOUNTABILITY, FAIRNESS, JUSTICE, EQUITY ETC", "question": "Identify and explain four foundamental qualities that ensure the survival of civil society", "images": [], "marking_scheme": "- Problem solving: Civil society is a dedicated and committed problem-solver,but it seems clear that it needs to step up its efforts to adapt to a new reality of rapidly changing interconnected problems.  - High ambitions and high expectations: The workload of civil society organizations has increased in the past few years,and with more work comes more responsibility and the need to manage expectations  - Difficult legislative and operational environment across the globe: The general trend towards more restrictive regulatory measures,increased controls,and funding restrictions by governments is unquestionably making it more challenging for certain civil society institutions to carry out their activities.  - Reworking the relationship with the private sector: Meanwhile,business have become more visibly engaged with social and environment agenda.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2020>9>b", "subject": "Civic Education", "year": "2020", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : PROBLEMS OF CIVIL SOCIETY; I.E. BRIBERY AND CORRUPTION, INADEQUATE FUNDING, THE OVERBEARING INFLUENCE OF FOREIGN DONORS ETC", "question": "List three challenges that continually threaten the existence of civil societies in Nigeria", "images": [], "marking_scheme": "- Bad limited resources  - Bad leadership  - Bad restricted participation", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2021>1>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : DEFINITION", "question": "What are values?", "images": [], "marking_scheme": "Values are basic and fundamental beliefs that guide or motivate attitudes or actions", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2021>1>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Elucidate six reasons why intergrity is the foundation of any functional society in the world", "images": [], "marking_scheme": "- Social relations: The concept of integrity has played a key role in moral philosophy throughout history and is promoted in all societies because of its importance to social relations.     - Vitality: Individual integrity is vital to society as the kind of society which is likely to be more conducive to integrity which is one which enables people to take up particular roles because of their sex or race or any other reason.     - Builds the confidence: Integrity builds the confidence and enables them to do more business than their competitors whose ethics may be a little unstable.     - Integrity is complete honesty in any situation. We must determine what is really right and really wrong. Right even transcends the violation of regulations.     - Intergrity means more to the professional officer than the dictionary definition. It means honesty, truthfulness, reliability, impartiality, sincerity, open mindedness, trustworthiness, and courage.     - An adequate account of personal integrity must be recognize that some social structures are of the wrong sort altogether for some individuals to be able to pursue personal integrity, and that questions about the moral nature of society.", "marks": "12", "difficulty": "3"}, {"id": "theory>Civic Education>2021>2>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND IDENTIFICATION OF THE SEVEN CORE FREEDOMS OF UDHR", "question": "Summarise the seven core freedoms a s established in the Charter of the Universal Declaration of Human Right (UDHR)", "images": [], "marking_scheme": "- Right to life, Liberty and security of the person     - Right to non-discrimination equality before the law and equal protection by the law     - Right to freedom of movement and to choose a residence     - Right to freedom of force labour, slavery-like practices and servitude     - Right to freedom and of thought, conscience and religion     - The right to peaceful assembly and freedom of association     - Right to freedom of opinion and expression", "marks": "7", "difficulty": "2"}, {"id": "theory>Civic Education>2021>2>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : ROLES OF INDIVIDUALS, GROUPS AND GOVERNMENT IN UDHR", "question": "In what four ways can individuals and groups contribute to upholding of the vision and mission of the Universal Declaration of Human right (UDHR)?", "images": [], "marking_scheme": "- Giving financial support to human rights abuse victims     - Individuals are expected to become conscious their right as citizens and be ready to claim it.     - Joining human rights group to promote respect for all human rights     - Willingness to report cases of human rights abuse to necessary authorities", "marks": "8", "difficulty": "2"}, {"id": "theory>Civic Education>2021>3>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : TRAFFIC REGULATION AND ITS IMPORTANCE IN THE SOCIETY", "question": "Identify five reasons road accidents in Nigeria could be seen as consequences of human's negligence", "images": [], "marking_scheme": "- Loss of productivity of the victims     - The cost of legal system     - The cost of pain and suffering     - loss of quality of life of the victim and their families     - Death and emotional damage     - depression and anxiety", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2021>3>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Highlight five explicit roles of government in mandating Nigerians to maintain traffic regulation.", "images": [], "marking_scheme": "- Education: Education and enlightenment campaigns on the road regulations, signals and signs.     - Setting up agency like FRSC that would implement traffic regulations     - Enacting traffic laws, regulations and policies and ensuring that the regulations are executed     - By making the road safe for the road users.     - Installing traffic lights and signs at appropriate traffic strategies     - Paying the safety agents and officials their salaries in time, so that they will be motivated to make our roads safe by doing their work     - providing the needed vehicles to do road safety work and also providing lowing vans that would evacuate a broken down vehicle     - Providing ambulances to raod safety agents and hospitals for easy evaluation of traffic crash victims", "marks": "10", "difficulty": "2"}, {"id": "theory>Civic Education>2021>4>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : MEANING AND ORIGIN OF CULTISM", "question": "Define a secret cult group", "images": [], "marking_scheme": "A secret cult group is refered to as a dangerous and deadly group that share common ideologies, believe in secret, esoteric, mystic and engage in violent practices.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2021>4>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "Explain four ways Civic Education can help eradicate involvement in cult activties in the society.", "images": [], "marking_scheme": "-Public campaign against cultism: Different organizations, including the government, schools , religious institutions and parent should promote awareness against cultism. Seminars and workshops should be organized to discuss the dnager of cultism all over schools without leaving out the primary schools     - Government standard: The government should also make laws to punish cultist for pushing away students and young people from joining these groups. The political leaders supporting them should also be put to judgment because they are damaging other children's live to make theirs better.     - Discipline and Studying hard in school to achieve success: Students should be kept busy and engage in school via curricular and extra curricular activities. Because it is a known fact that an \"idle mind is the devil's workshop\". When students are engage with hard work, they will not have time to join cult.     - Civic Education should be made compulsory in the primary and secondary schools in the country. Parent should take time to understand their children, give them enough time to listen to them at home and satisfy their emotional psychological and physical needs.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2021>5>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : SYMPTOMS AND EFFECTS OF HIV/AIDS", "question": "Outline five physical manifestation a person with Human Immunodeficiency Virus/Acquired Immune Deficiency Syndrome (HIV/AIDS) is bound to exhibit", "images": [], "marking_scheme": "- Rapid weight loss   - Recurring fever or profuse night sweats   - Pneumonia   - Diarrhea that lasts for more than a week   - Sores of the mouth, anus, or genitals   - Memory loss, depression and other neurological disorder", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2021>5>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : SYMPTOMS AND EFFECTS OF HIV/AIDS", "question": "Highlight five socio-economic effects of Human Immunodeficiency Virus/Acquired Immune Deficiency Syndrome (HIV/AIDS) on the carrier.", "images": [], "marking_scheme": "- HIV makes it hard to fight off respiratory problems such as the common cold and flu.     - HIV -positive person may develop related infections, such as pneumonia     - HIV-positive person at an even greater risk for infectious complications, such as tuberculosis and a fungal infection called pneumocystis jiroveci pneunomia(PJP)     - The risk of lung cancer also increases with HIV.This is due to weakened lungs from numerous respiratory issues related to a weakened immune system     - People with HIV are more likey to develop high blood pressure     - It also raises the risk of pulmonary arterial hypertension.     - HIV affects the immune system, it also makes the body more susceptible to infections that can affect the digestive system.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2021>6>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : MEANING OF YOUTH EMPOWERMENT", "question": "Define youth empowerment", "images": [], "marking_scheme": "Youth Empowerment is a development programme aimed at creating opportunities that will encourage and develop the youths to be morally responsible, self-reliant and financially productive citizens.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2021>6>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "Outline six youth enpowerment skills", "images": [], "marking_scheme": "-Life Coping Skills: These are natural skills which every organism including man, acquires from birth to adapt fittingly in his or its environment. They are survival instincts or skills     - Manipulative skills: These are skills seen in skills acquisition centres as it involves economic activties that inculcate skills such as technical education     - Intellectual skills: These skills are coordinates in character. It is the literay of theoretical frameworks that guide the practical aspects of the works, economic and scientific undertakings     - Communicative skills: Communication is a very important aspect of our life. Man evolved communications skills as a social being to enable him pass or send information from one person to the other or from place to place.     - Artistic skills: These are close to communicative skills and are more complex. Includes they art of good writing, fine and applied arts, music and drama. These skills make effective use of all the other four kinds of skills where necessary.     - Decision making skills: These can be the difference in making a choice that improves your organization. The aptitude to make decisions is a leadership trait, which portrays your ability to think objectively and relates concepts to the goals you are trying to reach.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2021>7>a>i", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "i", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain any three pillars of democracy from the list below:    - independence judiciary", "images": [], "marking_scheme": "Judicial independence, the ability of courts and judges to perform their duties free of influence or control by other actions, whether governmental or private.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2021>7>a>ii", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "ii", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain any three pillars of democracy from the list below:    - the millitary", "images": [], "marking_scheme": "Military government, administration of occupied territory by an occupying power, including the exercise of executive, legislative and judicial authority.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2021>7>a>iii", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "iii", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain any three pillars of democracy from the list below:    - politcal parties", "images": [], "marking_scheme": "Political parties are organized groups of people who share common ideas with the sole aim of contesting elections to gain/assume political power in a democratic state.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2021>7>a>iv", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "iv", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain any three pillars of democracy from the list below:    - Civil Society Organizations", "images": [], "marking_scheme": "These are private non-profit organizations formed to promote collectively shared values, interests and objectives that are capable of enhancing the general welfare and development of democratic states.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2021>7>a>v", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "v", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "Explain any three pillars of democracy from the list below:    - free and independent press.", "images": [], "marking_scheme": "This refers to a situation or condition in which media organizations are allowed to perform their functions of informing, educating, entertaining people and scrutinizing government activities without undue censorship for the purpose of good governance in a democracy.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2021>7>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF DEMOCRACY", "question": "Highlight three reasons why competition for political power among politicians is fierce in Nigeria.", "images": [], "marking_scheme": "- Provide incentive; Regular electoral competition provides incentives to political parties and leaders     - Victory: Political parties know that if they raise issues that people want to be raised their popularity and chances of victory will increase in the next elections     -If a political party is motivated only by the desire to be power, despite that, it will be forced to serve people.", "marks": "9", "difficulty": "2"}, {"id": "theory>Civic Education>2021>8>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : TRADITIONAL AND MODERN MODES OF POPULAR PARTICIPATION", "question": "Define modern mode of popular participation", "images": [], "marking_scheme": "Modern mode of popular participation is the mode of popular participation carried out through expressing of oneself through the mass media.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2021>8>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Explain six ways popular participation can facilitate the advancement of developing society", "images": [], "marking_scheme": "-Legitimacy of elected governments: If citizens actively participate in electoral process, society will have an elected legitimate government     - National development: There will be rapid socio-economic development if citizens participate in the electoral or political process.     - Political stability: This ensures law and order for economic and political development in the society.     - Responsible and responsive government; The society will elect or get a government that is receptive to the people's concerns and aspirations.     - Political awareness: When citizens participate in the electoral/political process, they will become politcally conscious, enjoy their rights and perform corresponding duties and obligations to the society.     - Credible elections: When citizens actively participate in the electoral or political process, it will confer credibility on the process.     - Peaceful order of succession: Peaceful transition is ensured from one regime to another     - Peace and harmony: When citizens actively participate in the political process, they will enjoy peace and harmony without much agitation     - Accountability, transparency, due process and probity: Active participation of citizens in the political process ensures accountability, transparency, due process and probity in governance for the common good of the society.", "marks": "12", "difficulty": "3"}, {"id": "theory>Civic Education>2021>9>a", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : MEANING OF PUBLIC SERVICE", "question": "Itemize five components of the public service in Nigeria", "images": [], "marking_scheme": "- It advices in the formation of the policies of government   - It implements government policies   - It advises the government   - It creates employment opportunities   - It performs delegated/legislative functions", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2021>9>b", "subject": "Civic Education", "year": "2021", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : REASONS FOR THE SHORTCOMINGS IN THE PUBLIC SERVICE", "question": "Advance five reasons for the ineffectiveness and inefficiency of public servants in Nigeria", "images": [], "marking_scheme": "- Poor remuneration: A hungry man is an angry man. The civil service are poorly remunerated which causes them to take bribe. The salary they receive is not even enough for them to pay their children's school fees. They are not well motivated.     - Absence of skilled manpower: Lack of skilled manpower in the civil service causes inefficiency in the civil service. Therefore, any organization that lacks adequate skilled personnel in their organization, will find it difficult carrying out their operations effectively and efficiently.     - Poor human resources management: Human resources management recruits and train workers to work in the organization. But when the organization cannot manage their workers, the workers tend to leave the organization. Poor management of workers causes death of an organization.     - Inadequate materials or insufficient materials: Lack of materials for work causes inefficiency in the operattions of the civil service. Government failures to provide those necessary materials that can facilitate work in offices contribute to the cause of ineffectivenesss in civil services.     - Corruption: Corruption has eaten deep into the bones of our civil service, it hard to find a civil servant without the intent to defraud. When corruption continues to thrive in the civil service, it affects the general operations of the civil service.", "marks": "10", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION A>1>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING OF HUMAN RIGHTS", "question": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATIONS    Define human rights.", "images": [], "marking_scheme": "Human rights are commonly understood as being those rights which are inherent in the mere fact of being human. Human rights are universal and inalienable; indivisible; interdependent and interrelated. They are universal because everyone is born with and possesses the same rights, regardless of where they live, their gender or race, or their religious, cultural or ethnic background. Inalienable because people's rights can never be taken away. Indivisible and interdependent because all rights – political, civil, social, cultural and economic – are equal in importance and none can be fully enjoyed without the others. They apply to all equally, and all have the right to participate in decisions that affect their lives. They are upheld by the rule of law and strengthened through legitimate claims for duty-bearers to be accountable to international standards.", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2022>SECTION A>1>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : LIMITATIONS TO THE EXERCISE OF HUMAN RIGHTS", "question": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATIONS  Suggest four conditions under which human rights can be violated in Nigeria.", "images": [], "marking_scheme": "-The police in enforcing law and order can ban public assembly and demonstrations which will deny a citizen his right to freedom of association and assembly.  -Rights to the freedom of expression and press are restricted by the law preventing individuals from saying or publishing statement that could damage the personality of others (laws of slander and libel).  -A citizen may be denied his rights to free movement if he is detained on medical ground in order not to spread contagious disease if such citizen is suffering from a contagious disease.  -Right to private property may be restricted by the right of the state to compulsorily acquire private property for public use.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION A>1>c", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : IMPORTANCE OF UDHR", "question": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATIONS  Explain three reasons for which it is necessary to entrench citizens' rights in the Nigerian constitution.", "images": [], "marking_scheme": "- Stability/Organization: Citizens' rights are entrenched in the constitution in order to have a well-arranged documentation of the rights of citizens in a country and since the constitution is the body of regulation that guides the affairs of a country, it is the most appropriate to house human rights.  - Understanding specifics of human rights: Human rights are entrenched in the constitution so that everyone can access them and understand the conditions surrounding these rights as well as their limitations.  - Rule of Law: The rule of law is a liberty centred constitutional concept which stipulates that everything must be done in accordance with the law. It encapsulates such ideals as government according to the law, equality before the law and the independence, and autonomy of the judiciary among others. This helps to make human rights applicable and efficient.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION A>2>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATIONS  Identify five qualities an individual must possess to be qualified as a responsible parent.", "images": [], "marking_scheme": "- The first quality of a responsible parent is marrying the right person yhat the children can emulate.  - The ability to provide the basic necessities for the family is another quality of a responsible parent.  - A responsible parent must be able to notice and solve whatever emotional imbalance arising in their children.  - A responsible parent must be able to plan the nymber of children to have and are capable of catering for.  - A responsible parent must be able to adopt peaceful strategies to always keep the family going.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION A>2>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : IMPORTANCE OF RESPONSIBLE PARENTHOOD IN NATIONAL DEVELOPMENT", "question": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATIONS  In what five ways do the roles of responsible parenting contribute to the upbringing of good citizens in the society?", "images": [], "marking_scheme": "- Teaching morality: Good citizens need to be people who act according to moral principles. Rather than being selfish or trying to deceive each other, they ought to deal in a kind and upright way with each other. Part of a parent's responsibility is ensuring that they bring up the next generation of citizens properly.    -Teaching social interactions: Being polite, making friends, and reaching out to others are all important things in society. Parents can teach children to be comfortable when socializing from an early age.    -Encouraging independent thought: In a democratic society, or indeed in any society, good citizenship involves expressing one's opinions, and also respecting the opinions of others. This is seen not least in the voting process. Responsible parenthood, then, also involves teaching children to respect others' opinions – and to develop their own opinions too. Tolerance of others is a true civic virtue.    -Appreciating the society: Children will not grow up to become responsible citizens unless they appreciate the society in which they live. Thus, part of responsible parenting may well include taking children out to enjoy public parks, theatre productions and so on in the city.    -Becoming responsible parents too: Our parenting style will often inspire our children when they become parents in their turn. So, being responsible parents is so important if we want our children to become responsible parents in their own right. In so doing, we become part of an established tradition of good parenting that helps to shape our society to get better and better.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2022>SECTION A>3>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATIONS  Identify five reasons for which it has become increasingly difficult to maintain low rate of accidents on Nigerian roads.", "images": [], "marking_scheme": "- Poor functional roads: Many accidental occurance while driving in Nigeria is as a result of bad roads. Many of our roads are inaccessible, too narrow, not developed, full of potholes.    -Bad vehicle/motor maintenance culture in Nigeria: Many people fail to engage in simple maintenance check and servicing of their vehicle such as the break, tires, steering etc.    -Poor driving behaviour: Many Nigerians usually throw caution into the wind when driving. They drive recklessly trying to overtake other's vehicle like it's a car racing competition, and also fail to adhere to simple traffic and driving rules and regulations.    -Lack of proper driving education: Many drivers didn't attend driving school, so they are not well-informed about certain driving rules, skills and safety tips.    -Use of mobile devices and gadgets while driving: Even with several warnings from government agencies concerning transportation, people still engage in dangerous behaviours such as making calls when driving, reading and replying text messages, driving while watching videos from the car.", "marks": "5", "difficulty": "3"}, {"id": "theory>Civic Education>2022>SECTION A>3>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : TRAFFIC REGULATION AND ITS IMPORTANCE IN THE SOCIETY", "question": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATIONS  Highlight five measures that can be adopted by the Nigerian government to reduce the rate of accidents on Nigerian roads.", "images": [], "marking_scheme": "-Sanitation of motor parks from alcohol sales and consumption  Shops where alcoholic beverages are sold are visibly present in most if not all Nigerian motor parks today without recourse to the very negative effects of drunk drinking by drivers who are the main consumers. The resultant effect is reckless driving on our Highways. There needs to be proper enactment of legislations to address this issue and thorough enforcement of legislations already put in place forbidding the sales of alcoholic drinks or beverages in our motor parks.     -Routine maintenance and rehabilitation of road pavements.   Bad road pavement conditions in Nigeria are one of the principal causes of road accidents. These roads are poorly constructed and rarely managed or rehabilitated. When these roads are not maintained and rehabilitated, they tend to deteriorate. Therefore a remote way of ensuring accident reduction/prevention is for the government, which is charged with the responsibility for good maintenance to draw up and implement to the later on regular basis, budgets that match the demands of the road network and its infrastructure.    -Total prohibiting the use of mobile phones while driving  While there is little concrete evidence yet on how to reduce mobile phone use while driving, the Nigerian government needs to be proactive. Actions that can be taken to address this ill tradition by Nigerians include enacting, adopting and fully enforcing legislative measures prohibiting the use of mobile phones while driving.    -Training and retraining/public enlightenment  The road traffic system itself is dynamic in nature. Hence training and retraining of drivers constitute a formidable means of effectively dealing with the issue of road traffic accident reduction. In Nigeria today, major road traffic accident scenes have been noticed to involve commercial transporters/vehicles. To this end, there is urgent need for public transport operators to ensure that their drivers are trained and retrained in collaboration with the Federal Road Safety Commission, FRSC.    -Diligence of duty by government established agencies  Government should ensure that all established agencies such as Federal Road Safety Commission, FRSC and Vehicle Inspection Offices, VIO must carry out their jobs effectively and thoroughly; checking the conditions of vehicles that ply on our road, without extorting money or collecting bribes from drivers.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2022>SECTION B>4>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "EMERGING ISSUES IN THE SOCIETY    Outline five negative consequences of cultism on its members in the society.", "images": [], "marking_scheme": "-Untimely Death  One of the pathetic effects of cultism is the loss of lives prematurely. The government through its law enforcement agencies on a constant effort, fights crime such as armed robbery, kidnapping, drug abuse, murder etc. carried out by the cult members.The outcome of such operations often results in exchange of fire, arrest, detention, imprisonment and death. Many young people who indulge in these heinous acts have lost their lives either in the course of a shootout confrontation or through inter-cult clashes.    -Loss of Moral Values  Cultism leads to loss of values in young people. This is because the belief system and ideologies of most of these cult groups are against the objective morality of life.    -Incomplete Education  Most cultists end up not completing their academic programme. Today, school authorities in a bid to curb the rate of cultism and its activities, have adopted strict penalties for it which include expulsion of students involved irrespective of the academic level they are.    -Drug and substance Addiction  Furthermore, drug addiction can be as a result of influence of cultism among our youths. Within the circle of fellow cult members, they are constantly exposed to drugs through the network of dealers on such substances who are regularly patronized by these cultists.    -Unrealizable Life Ambitions  Also cultism can lead to termination of ambitions and goals in youths. Most young people with bright future and potentials, end up not pursuing their career or goals because of the negative influence of cultism.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION B>4>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "EMERGING ISSUES IN THE SOCIETY  In what five ways can responsible parenting assist in reducing high rate of cultism in the society?", "images": [], "marking_scheme": "- Parents should pay more attention to their children's upbringing and educate  them properly on acceptable standards of behaviour.    - Parents should encourage their children to join religious groups and develop the fear of  God because the fear of God is the beginning of wisdom.    -Parents should show good examples to their children.    -Parents should keep an eye on the company that their children keep so that they can know when they start keeping bad company and keep them in check.    -Parents should join hands with other concerned individuals in the country to put measures in place to curb cultism.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2022>SECTION B>5>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "EMERGING ISSUES IN THE SOCIETY  Outline five reasons for which those who tested positive to HIV/AIDS are being discriminated against in the society.", "images": [], "marking_scheme": "-Fear is a common cause of discrimination. This may be fear of catching the disease as it is infectious (or perceived to be so).    -Discrimination by association is also known as 'symbolic stigma'. This may occur when a health condition is associated with a condition that is perceived to be undesirable. HIV/AIDS is an example of such as it is usually associated with illicit sex.    -Values and beliefs can play a powerful role in creating or sustaining stigma. Examples are beliefs regarding the cause of a condition. Religious values regarding sexual relationships and marriage may cause HIV/AIDS discrimination if they are perceived to be the result of marital infidelity.    -Lack of awareness and education on the nature of HIV/AIDS is another reason for the discrimination.    -In accurate and misleading representation even by some health workers is a cause of the discrimination of HIV/AIDS patients.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION B>5>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : SYMPTOMS AND EFFECTS OF HIV/AIDS", "question": "EMERGING ISSUES IN THE SOCIETY  In what five ways does the contraction of HIV/AIDS Impact on the socio-economic life of the victim?", "images": [], "marking_scheme": "- Loss of income and livelihood.  - It makes them dependent on others as they cannot be fully effective.  - Liable to become poor as they have to spend more even after losing their means of livelihood.  - The HID/AIDS patient becomes depressed while the family goes through emotional and psychological torture.  - The parents and relations who are shouldering the big financial responsibility of caring for the HID/AIDS patient may not be able to send other members of the family to school. In other words, the family is badly affected economically.", "marks": "10", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION B>6>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : YOUTH EMPOWERMENT SKILLS", "question": "EMERGING ISSUES IN THE SOCIETY  Highlight five major empowerment skills that youths require for self-reliance in Nigerian society?", "images": [], "marking_scheme": "-Life Coping Skills  These are natural skills which every organism including man, acquires from birth to adapt fittingly in his or its environment. They are survival Instincts or skills. They are natural things we do to survive, avert dander and assert our individuality, e.g., crude farming, running on an errand, hunting, learning to make shelter, fishing, obeying laws and authorities, avoiding conflicts, etc these skills graduate from simple crude form to a more complex, learned and modernized forms.    -Manipulative Skills  These skills are seen in skills acquisition centres as it involves economic activities that inculcate skills such as technical education. Computer, field events, mining, manufacturing, technological works, scientific experiments, construction, engineering, productive ventures, gadgets and machine manipulations (whether digital or analogue), building, wielding, carpentry, mechanics etc.    -Intellectual Skills  These skills are coordinates in character. It is the literary or theoretical frameworks that guide the practical aspects of the works, economic and scientific undertakings. In the primary sense, it is called brain work. Without the intellectual skills, no other skills can function as they are the master minds, motivators and co-coordinators. It is the engine of all activities generating the initiative and innovations in all their designs.    -Communicative Skills  Communication is a very important aspect of our life. Man evolved communications skills as a social being to enable him pass or send information from one person to the other or from place to place. Communicative skills assist the intellectual skills to be expressed adequately and specifically.     -Artistic Skills:    These are close to communicative skills and are more complex. Includes they art of good writing, fine and applied arts, music and drama. These skills make effective use of all the other four kinds of skills where necessary. Those who employ or have these skills are said to be adepts or experts, examples: Artists, Graphic designers, Musicians, Comedians, Actors, Actresses, etc. life coping skills agree with the artisan identity, the intellectual skills agree with the manager identity while the rest agree with the classical entrepreneur identity. Skills can be generally divided into two, namely, craftsman and entrepreneurial skills which tally with the life coping skills, manipulative skills and opportunistic entrepreneurial skills which match with the intellectual, artistic and communicative skills.", "marks": "5", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION B>6>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "EMERGING ISSUES IN THE SOCIETY  State five reasons for the establishment of the National Youth Service Corps (NYSC) in Nigeria.", "images": [], "marking_scheme": "- To develop common ties among the Nigerian youths and promote national unity and integration.  -To raise the moral tone of the Nigerian youths by giving them the opportunity to learn about higher ideals of national achievement, social and cultural improvement.  -To develop in the Nigerian youths the attitudes of mind, acquired through shared experience and suitable training. which will make them more amenable to mobilisation in the national interest.  -The equitable distribution of members of the service corps and the effective utilization of their skills in area of national needs.  -To encourage corps members to eschew religious intolerance by accommodating religious differences.", "marks": "10", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION C>7>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PILLARS OF DEMOCRACY", "question": "GOVERNMENTAL SYSTEM AND PROCESSES    Define political party as a pillar of democracy.", "images": [], "marking_scheme": "Political parties are a group of persons organized to acquire and exercise political power. Citizens vote for the party of their choice and, in this way, influence government policy. The presence of the political party is actually a healthy situation for the nation. It gives people a choice to make a more evolved and effective decision. Political parties are essential institutions of democracy. By competing in elections parties offer citizens a choice in governance, and while in opposition they can hold governments accountable.", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2022>SECTION C>7>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "GOVERNMENTAL SYSTEM AND PROCESSES  Highlight six ways of enhancing the credibility of democratic elections in Nigeria.", "images": [], "marking_scheme": "- In order for citizens to make informed choices at the ballot box, they need accurate information about the candidates and political platforms they're choosing between. This means that governments can't prevent the media from covering opposition candidates or parties, and it also means that parties don't intentionally spread misinformation. So access to reliable information is a key requirement for credibility of democratic elections.    -In a democracy with free and fair elections, governments exist for the people, are empowered by the people, and are made up of the people. A citizen who is eligible to vote should also be eligible to run for office. Governments cannot attack or prevent people who want to run for office, assuming they meet the same eligibility criteria as other politicians and candidates.    -Even if voters are given the right to vote, and are able to register to vote, an election is not free and fair unless they are then able to actually cast their ballot. Governments need to make voting reasonably possible for citizens. They must not be overly burdened to reach polling places, and reasonable accommodation should be made to ensure that citizens with a disability or other health condition, or lack of transportation, are still able to vote.    -Nobody should be intimidated or threatened at any point during an election. This includes outside and inside the polling station, but also before election day. The threat of violence can make people afraid to vote their preference. The threat of violence also does not need to be overt to violate this standard. If the government staffs polling places with poll watchers who are intentionally intimidating looking, or even armed, this can intimidate voters. So too can having people observe the actual process of voting. This is why secret ballots are important to ensure that voters feel safe and secure while voting.    -Every eligible voter should be able to cast one ballot, and it should be counted the same as every other ballot. When illegal ballots are counted along with legal ballots, the result does not reflect the will of voters.    -Counting all ballots and giving an accurate reporting of that count are essential parts of a free and fair election. Ballots must not be altered or thrown out after they are cast. And when a fair count is done, the government cannot refuse to release it, or release a different result.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2022>SECTION C>8>a", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Explain the following forms of civic society.    Pro-democracy groups", "images": [], "marking_scheme": "These are groups that do everything withing their legal capacity to uphold the democratic principles of a state. They achieve their goals through protest most times and have a sole aim of keeping the will of the people.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2022>SECTION C>8>b", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Explain the following forms of civic society.  Labour groups", "images": [], "marking_scheme": "A labour union/group is an organization of employees that is created for the purpose of dealing with employers concerning employee-employer relations, including grievances, labor disputes, wages, rates of pay, hours of employment, and other conditions of work. A labor union negotiates on behalf of its members in a process known as collective bargaining. They are also usually active in the political process and in lobbying about issues of importance to their members.", "marks": "2", "difficulty": "1"}, {"id": "theory>Civic Education>2022>SECTION C>8>c", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "c", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Explain the following forms of civic society.  Professional groups", "images": [], "marking_scheme": "A professional association/group is an organization with members who work in or share an interest in a specific job field or industry. Members of professional associations will often meet regularly to discuss upcoming news in their field or will host events for other members to meet and network.", "marks": "2", "difficulty": "1"}, {"id": "theory>Civic Education>2022>SECTION C>8>d", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "d", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Explain the following forms of civic society.  Religious groups", "images": [], "marking_scheme": "A religious group is a set of individuals whose identity as such is distinctive in terms of common religious creed, beliefs and doctrines. They are gatherings of individuals who have common religious beliefs, habits, and practices and ideologies about the negotiated order of these gatherings.", "marks": "2", "difficulty": "1"}, {"id": "theory>Civic Education>2022>SECTION C>8>e", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "e", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Explain the following forms of civic society.  Student groups", "images": [], "marking_scheme": "A​ ​student​ ​organization​ ​is defined as a group of undergraduate or graduate students who unite to promote or celebrate a common interest. The purpose of a student organization is to bring everyone together based on their interests and build relations. Student organization recognitions purpose is to create connections, expand skills, and explore different elements of university life while making lifelong friends.", "marks": "2", "difficulty": "1"}, {"id": "theory>Civic Education>2022>SECTION C>8>f", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "f", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Explain the following forms of civic society.  Gender groups", "images": [], "marking_scheme": "The Gender Group is a closed support/social group for people who self-identify as male or female, or may be identified by others, as transgender, genderqueer, bigender, crossdresser, or any other identity that may fall under the umbrella of trans.", "marks": "2", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION C>8>g", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "g", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF CIVIL SOCIETY", "question": "Explain the following forms of civic society.  Human rights groups", "images": [], "marking_scheme": "Human rights are rights inherent to all human beings, regardless of race, sex, nationality, ethnicity, language, religion, or any other status. A human rights group, or human rights organization, is a non-governmental organization which advocates for human rights through identification of their violation, collecting incident data, its analysis and publication, promotion of public awareness while conducting institutional advocacy, and lobbying to halt these violations.", "marks": "2", "difficulty": "2"}, {"id": "theory>Civic Education>2022>SECTION C>9", "subject": "Civic Education", "year": "2022", "type": "Theory", "sub_label": "9", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : PROBLEMS OF PUBLIC SERVICE", "question": "Enumerate five reasons for which the public service in Nigeria has not been proficient.", "images": [], "marking_scheme": "-Bribery and Corruption: The quick, smooth operation of the civil service is often handicapped by bribery and corruption. Some public servants no longer do their official duty, rather they are looking forward to being bribed before doing their duties.    -Mode of employment: MOST (not all) employment into the public service is not mainly on merit. Employment is given to those that are highly connected or those that are ready to pay for the employment. Some of these people may not be qualified for the job and these will affect the level of productivity. Sometimes, the unqualified person is appointed or promoted to a position he cannot perform well, while the qualified person is passed over due to favoritism.    -Bottleneck in Administrative procedure: The Nigerian Public Service is govern by its constitution (Public Service Rules), employment, retirement and sacking of Civil Servants are done by or with the permission of the Federal Civil Service Commision (FCSC). This means that as an employee, your boss cannot sack you. He can only give you a query or make complains to the FCSC. This makes most workers to misbehave and engage in different misconduct.    -Duplication of offices and position: The public service is often criticized for wasting financial and manpower resources, and retaining unproductive workers with the creation of ministries, departments and positions with similar functions.    -Ineffective organization: The public service has been touted as being ineffectively organized, and improperly managed. For instance, records, documents, files and other sources of information are not well arranged nor properly coordinated. This may be due to frequent movement of workers or non-delineation of responsibilities.", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2023>1>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : VALUES : IMPORTANCE OF VALUES TO SOCIETY", "question": "Identify five values of civic education", "images": [], "marking_scheme": "Civic education is a vital aspect of any country's educational curriculum as it helps to instill certain values in the citizens. Five values of civic education include:   - Respect for human dignity: Civic education teaches individuals to respect the dignity of all humans irrespective of their race, religion, or social status.   - Equality: It promotes the idea that all individuals are equal and should be treated as such.   - Justice: Civic education instills the value of justice in individuals, teaching them to be fair in all their dealings.   - Rule of law: It teaches the importance of laws and the need to abide by them.   - Patriotism: Civic education instills a sense of patriotism in individuals, making them love and respect their country.", "marks": "5", "difficulty": "1"}, {"id": "theory>Civic Education>2023>1>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : GOALS OF CITIZENSHIP EDUCATION", "question": "Explain any five ways citizenship education can contribute to nation building", "images": [], "marking_scheme": "Citizenship education plays a crucial role in nation-building in the following ways:   - Promotes Unity: It teaches citizens about the importance of unity and how it contributes to the development of the nation.   - Encourages Participation: It encourages citizens to participate in the democratic process, thereby contributing to the decision-making process.   - Instills Patriotism: It instills a sense of patriotism in citizens, making them more committed to the development of their nation.   - Promotes Respect for Law and Order: It teaches citizens the importance of law and order, thereby reducing crime rates.   - Encourages Volunteerism: It encourages citizens to volunteer their time and resources for the development of the nation.", "marks": "10", "difficulty": "2"}, {"id": "theory>Civic Education>2023>2>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY", "question": "Outline three factors that determine the legitimacy of a constituted authority in the society", "images": [], "marking_scheme": "The legitimacy of a constituted authority in society is determined by the following factors:   - Consent of the Governed: The authority must be established with the consent of the people. This is usually achieved through elections.   - Rule of Law: The authority must operate within the confines of the law. Any authority that operates outside the law is considered illegitimate.   - Respect for Human Rights: The authority must respect and protect the human rights of the citizens. Any authority that violates human rights is considered illegitimate.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2023>2>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY", "question": "Highlight six factors that facilitates citizens' obedience to constitued authority in Nigeria", "images": [], "marking_scheme": "The following are six factors that facilitate citizens' obedience to constituted authority in Nigeria:   - Education: When citizens are educated about the importance of obeying the law, they are more likely to do so.   - Fear of Punishment: The fear of punishment for disobedience can also make citizens obey the law.   - Respect for Authority: When citizens respect the authority, they are more likely to obey the law.   - Good Governance: When the government is transparent and accountable, citizens are more likely to obey the law.   - Economic Incentives: Economic incentives such as tax breaks can also encourage citizens to obey the law.   - Cultural Values: In some cultures, obedience to authority is a deeply ingrained value.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2023>3>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS", "question": "Define inter-communal relationships", "images": [], "marking_scheme": "Inter-communal relationships refer to the relationships between different communities. These relationships can be social, economic, political, or cultural in nature. They involve interactions between different communities that lead to mutual understanding, cooperation, and respect for each other's values and traditions. Inter-communal relationships are crucial for promoting peace, unity, and development within a country.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2023>3>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "Explain fourways by which inter-communal relationships promote community development in Nigeria", "images": [], "marking_scheme": "Inter-communal relationships promote community development in Nigeria in several ways. First, they foster unity and peace. When communities have good relationships with each other, there is less likelihood of conflict, which creates a peaceful environment for development. Second, inter-communal relationships encourage cooperation. Communities can work together to achieve common goals, such as building infrastructure or improving education. Third, they promote cultural exchange. This can lead to a better understanding and appreciation of different cultures, which can in turn lead to more harmonious coexistence. Fourth, inter-communal relationships can lead to economic growth. When communities trade with each other, it can stimulate economic activity and lead to increased prosperity.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2023>4>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : GOVERNMENT AGENCIES WORKING TO PREVENT DRUG ABUSE/TRAFFICKING AND THEIR ACTIVITIES", "question": "List **three government agencies that are constitutionally empowered to arrest persons who commit drug -related offence in Nigeria", "images": [], "marking_scheme": "Three government agencies that are constitutionally empowered to arrest persons who commit drug-related offences in Nigeria are:   - The National Drug Law Enforcement Agency (NDLEA), which is the primary agency responsible for tackling drug offences.   - The Nigeria Police Force, which has the power to arrest and prosecute any person who commits a crime, including drug offences.   - The Economic and Financial Crimes Commission (EFCC), which can arrest persons involved in drug trafficking if it is linked to financial crimes.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2023>4>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : HOW DRUGS ARE ABUSED", "question": "In what six ways can non-adherence to medical advice of certified medical professionals constitute a threat to the survival of the sick and the society?", "images": [], "marking_scheme": "Non-adherence to medical advice of certified medical professionals can constitute a threat to the survival of the sick and the society in several ways. First, it can lead to the worsening of the patient's condition, which can result in death. Second, it can lead to the spread of infectious diseases. If a patient does not follow medical advice, they may not take the necessary precautions to prevent spreading the disease. Third, it can lead to antibiotic resistance, which is a major public health concern. Fourth, it can increase healthcare costs, as patients who do not follow medical advice may require more intensive treatment later on. Fifth, it can lead to unnecessary suffering for the patient. Sixth, it can strain healthcare resources, as non-adherence can lead to increased hospital admissions.", "marks": "12", "difficulty": "3"}, {"id": "theory>Civic Education>2023>5>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : CAUSES OF HIV/AIDS", "question": "Highlight three major ways by which HIV/AIDS can be contracted", "images": [], "marking_scheme": "HIV/AIDS can be contracted in several ways. First, it can be transmitted through unprotected sexual intercourse with an infected person. Second, it can be contracted through sharing needles or syringes with someone who is infected. Third, it can be transmitted from an infected mother to her baby during childbirth or breastfeeding.", "marks": "6", "difficulty": "1"}, {"id": "theory>Civic Education>2023>5>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "State three reasons why the eradication of HIV/AIDS is still problematic in Nigeria", "images": [], "marking_scheme": "The eradication of HIV/AIDS is still problematic in Nigeria for several reasons. First, there is a lack of awareness and education about the disease, which can lead to risky behaviors. Second, there is a stigma associated with HIV/AIDS, which can prevent people from getting tested or seeking treatment. Third, there are challenges in accessing healthcare, including the cost of treatment and the availability of healthcare facilities.", "marks": "9", "difficulty": "2"}, {"id": "theory>Civic Education>2023>6>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : CONSEQUENCES OF CULTISM", "question": "Enumerate six consequences of cultism in the society", "images": [], "marking_scheme": "Cultism in society has several consequences. These include:   - Loss of lives and property: Cultism often leads to violent clashes where lives are lost and properties destroyed.   - Disruption of academic activities: In schools, cult activities often disrupt academic work, leading to frequent closures of schools.   - Moral decadence: Cultism promotes immoral activities and erodes the moral values of the society.   - Insecurity: The activities of cultists create an atmosphere of fear and insecurity.   - Poor societal development: Resources that could have been used for societal development are often used to repair damages caused by cult activities.   - Stigmatization: Members of the society who are known to be cultists are often stigmatized and discriminated against.", "marks": "6", "difficulty": "2"}, {"id": "theory>Civic Education>2023>6>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "EMERGING ISSUES IN THE SOCIETY : CULTISM : WAYS OF PREVENTING CULTISM IN SOCIETY", "question": "State **three* hindrances to the eradication of cultism in Nigeria", "images": [], "marking_scheme": "There are several hindrances to the eradication of cultism in Nigeria. These include:   -  Poor enforcement of laws: The laws against cultism are not effectively enforced.   - Corruption: Some law enforcement officers are corrupt and often compromise when dealing with cultists.   - Societal acceptance: Some members of the society see cultism as a norm and this makes it difficult to eradicate.", "marks": "9", "difficulty": "2"}, {"id": "theory>Civic Education>2023>7", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "7", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : PUBLIC SERVICE IN DEMOCRACY : FUNCTIONS OF PUBLIC SERVICE", "question": "Explain five functions of public service in Nigeria", "images": [], "marking_scheme": "Public service in Nigeria has several functions. These include:   - Implementation of government policies: Public service is responsible for the implementation of government policies.   - Provision of services: Public service provides services to the public such as healthcare, education, and infrastructure.   - Regulation: Public service regulates the activities of individuals and organizations in the country.   - Collection of revenue: Public service collects revenue for the government through taxes and levies.   - Maintenance of law and order: Public service helps in maintaining law and order in the country.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2023>8>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Name five alternative strategies desperate politicians are likely to use to win elections", "images": [], "marking_scheme": "Desperate politicians are likely to use several strategies to win elections. These include:   - Vote buying: They may offer money or gifts to voters in exchange for their votes.   - Use of thugs: They may employ thugs to intimidate opponents and voters.   - Rigging: They may manipulate election results in their favor.   - False propaganda: They may spread false information about their opponents to discredit them.   - Abuse of power: If they are in power, they may use state resources to their advantage.", "marks": "5", "difficulty": "3"}, {"id": "theory>Civic Education>2023>8>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : ACHIEVING POPULAR PARTICIPATION IN POLITICS", "question": "Explain five effective measures that could be taken to checkmate desperate politicians from winning elections at all cost", "images": [], "marking_scheme": "Several measures could be taken to checkmate desperate politicians from winning elections at all cost. These include:   - Strengthening of electoral laws: The electoral laws should be strengthened to punish electoral offenses.   - Voter education: Voters should be educated on the dangers of selling their votes.   - Independent judiciary: The judiciary should be independent to adjudicate electoral disputes fairly.   - Security: Adequate security should be provided during elections to prevent violence and intimidation.   - Transparency: The electoral process should be transparent to ensure that the will of the people prevails.", "marks": "10", "difficulty": "3"}, {"id": "theory>Civic Education>2023>9>a", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Explain the executive arm of government in Nigeria", "images": [], "marking_scheme": "The executive arm of government in Nigeria is one of the three arms of government, the other two being the legislative and the judicial arms. The executive arm is responsible for implementing and enforcing laws and policies made by the legislative arm. It is headed by the President, who is the Chief Executive Officer of the federation. The President is assisted by the Vice President, Ministers, and other government officials. The executive arm also includes the civil service, which is responsible for the day-to-day administration of the country. The executive arm has the power to formulate and implement policies, maintain law and order, ensure national security, and administer the state's resources for the welfare of the citizens.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2023>9>b", "subject": "Civic Education", "year": "2023", "type": "Theory", "sub_label": "b", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : HOW DEMOCRACY AND RULE OF LAW PROMOTE NATIONAL DEVELOPMENT- GOOD GOVERNANCE, EMPLOYMENT CREATION AND POVERTY ALLEVIATION ETC", "question": "In what six ways do the constitutional roles of the executive arm of government promote democracy?", "images": [], "marking_scheme": "The constitutional roles of the executive arm of government promote democracy in several ways.   - Rule of Law: The executive enforces the rule of law, ensuring that all citizens are treated equally under the law.   - Protection of Rights: The executive protects the rights and freedoms of citizens as enshrined in the constitution.   - Implementation of Policies: The executive implements policies that are beneficial to the citizens, promoting their welfare and well-being.   - Maintenance of Order: The executive maintains law and order, ensuring a peaceful and conducive environment for democratic processes to take place.   - Representation: The executive, being elected by the people, represents the will of the people in governance.   - Checks and Balances: The executive checks the powers of the other arms of government, preventing the abuse of power and promoting accountability and transparency in governance.", "marks": "12", "difficulty": "3"}, {"id": "theory>Civic Education>2024>SECTION A>1>a", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : MEANING OF GOVERNMENT", "question": "Mention three bases of emergence of constituted authority in the society.", "images": [], "marking_scheme": "The emergence of constituted authority in society is based on several factors:    Tradition: Authority arises from long-established customs, with leaders often selected based on hereditary or cultural practices.    Legal Frameworks: Constituted authority can emerge from formal laws, with power conferred through elections or appointments under a legal system.    Divine Right or Religion: In some societies, leaders claim authority based on religious or spiritual justification.    Consent of the Governed: Authority is also established through social contracts where people voluntarily cede some freedom for order.    Force or Conquest: Some authorities emerge through power or domination.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION A>1>b", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Explain any six roles of traditional leaders in a democratic society.", "images": [], "marking_scheme": "Traditional leaders play significant roles in a democratic society, often blending cultural heritage with modern governance:    Cultural Preservation: Traditional leaders act as custodians of their people's customs, traditions, and values. They ensure that these are passed down through generations, helping maintain cultural identity in a rapidly changing world.    Conflict Resolution: In many communities, traditional leaders serve as mediators in disputes, using customary law to settle conflicts. Their deep knowledge of local customs often makes them effective at resolving issues peacefully.    Community Representation: Traditional leaders often act as a bridge between their communities and formal government structures. They represent their people's interests, voicing concerns to elected officials and ensuring their community's needs are addressed.    Advisory Role: In a democratic society, traditional leaders can serve as advisors to government officials, especially on issues affecting rural or indigenous communities. Their insights help create policies that respect cultural practices.    Development Advocacy: Traditional leaders can mobilize communities for development projects, promoting education, health, and infrastructure initiatives while ensuring government programs reach the grassroots.    Moral Leadership: As respected figures, traditional leaders often uphold moral values and provide guidance on ethical behavior, reinforcing community bonds and contributing to social cohesion. Their influence promotes stability and unity within democratic systems.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION A>2>a", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : IMPORTANCE OF INTER-COMMUNAL RELATIONSHIPS", "question": "Explain community services.", "images": [], "marking_scheme": "Community services refer to voluntary activities performed by individuals or groups to benefit the public or a specific community. These services aim to improve the well-being of the community by addressing social, environmental, or economic needs. Examples include cleaning public spaces, organizing educational programs, offering free medical camps, or assisting vulnerable groups like the elderly and homeless. Community service promotes civic responsibility, fosters unity, and helps individuals develop a sense of empathy and connection with others. It is often seen as a way to give back to society, improving the quality of life for all members of the community.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION A>2>b", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : INTER-PERSONAL RELATIONSHIPS : MEANING OF INTER-COMMUNAL RELATIONSHIPS~~NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : IMPORTANCE AND ROLES OF CONSTITUTED AUTHORITY", "question": "Outline any six benefits of community services.", "images": [], "marking_scheme": "Community services offer numerous benefits to individuals and society as a whole:    Enhanced Community Cohesion: By participating in community service, individuals work together towards common goals, fostering a sense of unity and solidarity. This helps build strong, interconnected communities where people support and trust one another.    Improved Quality of Life: Community services often address pressing local needs such as health, education, and environmental issues. Initiatives like free clinics, tutoring programs, and clean-up drives contribute to better living conditions and overall well-being.    Skill Development: Volunteers gain valuable skills through community service, including leadership, teamwork, and problem-solving abilities. These skills enhance personal growth and can be beneficial in professional and personal contexts.    Increased Civic Responsibility: Engaging in community service fosters a sense of civic duty and encourages individuals to actively contribute to the welfare of their society. It cultivates an understanding of social issues and the importance of participating in democratic processes.    Emotional and Psychological Benefits: Volunteering can lead to increased happiness and reduced stress. The act of helping others often provides a sense of fulfillment and purpose, boosting overall mental well-being.    Strengthened Social Networks: Community service helps build connections with diverse groups of people, expanding social networks. These relationships can provide support, friendship, and a sense of belonging, enhancing personal and professional opportunities.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION A>3>a", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : FEATURES OF LAW AND ORDER", "question": "List three road users.", "images": [], "marking_scheme": "Three road users include:    Drivers: Individuals operating motor vehicles like cars, trucks, and buses.  Cyclists: People riding bicycles, often on designated lanes or roads.  Pedestrians: Individuals walking on sidewalks, crosswalks, or near roadways, including those using mobility aids.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2024>SECTION A>3>b", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : FEATURES OF LAW AND ORDER", "question": "Describe six requirements that road users must comply with to ensure safer roads.", "images": [], "marking_scheme": "To ensure safer roads, road users must comply with several essential requirements:    Adherence to Traffic Laws: Road users must follow speed limits, traffic signals, and road signs to prevent accidents. Observing these laws ensures orderly traffic flow and reduces the risk of collisions.    Use of Safety Gear: Drivers should wear seat belts, and motorcyclists must wear helmets. Cyclists and pedestrians should use reflective clothing or gear, especially at night, to increase visibility and reduce injury in case of an accident.    Avoidance of Distractions: Drivers must avoid using mobile phones, eating, or engaging in other distractions while driving. Maintaining full attention on the road helps in making timely decisions and reacting to potential hazards.    Sobriety: Road users should never drive under the influence of alcohol or drugs. Impairment significantly increases the risk of accidents by affecting reaction times and decision-making abilities.    Respect for Pedestrian Rights: Drivers must yield to pedestrians at crosswalks and exercise caution in areas with heavy foot traffic. Ensuring pedestrian safety helps prevent accidents involving individuals on foot.    Proper Vehicle Maintenance: Regular vehicle inspections and maintenance, such as checking brakes, tires, and lights, are crucial. Well-maintained vehicles are less likely to break down or cause accidents due to mechanical failures.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION B>4", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "4", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : WAYS OF PREVENTING DRUG ABUSE", "question": "Highlight five ways substance abuse can be curbed in various institutions of learning.", "images": [], "marking_scheme": "ubstance abuse in educational institutions can be curbed through several effective strategies:    Education and Awareness Programs: Implementing comprehensive education programs about the dangers of substance abuse helps students understand the risks and consequences. These programs can include workshops, seminars, and interactive sessions that promote healthy lifestyles and provide information on avoiding substance use.    Counseling and Support Services: Providing access to counseling services where students can seek help for substance abuse issues or related stress can be crucial. Support groups and one-on-one counseling create a safe environment for students to discuss their struggles and receive professional guidance.    Strict Policies and Enforcement: Institutions should establish clear, strict policies against substance use, with defined consequences for violations. Regular enforcement and monitoring of these policies help deter potential substance abuse and maintain a safe learning environment.    Parental and Community Involvement: Engaging parents and community members in substance abuse prevention efforts can enhance support systems for students. Collaborating with families and local organizations can reinforce the message of substance abuse prevention and provide additional resources.    Promoting Healthy Activities: Encouraging participation in extracurricular activities, sports, and hobbies can offer students positive outlets and reduce the likelihood of substance abuse. Providing engaging alternatives helps students build resilience and find fulfillment outside of substance use.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION B>5>a", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : PREVENTION OF HIV/AIDS", "question": "Mention five ways HIV/AIDS can be prevented.", "images": [], "marking_scheme": "HIV/AIDS can be prevented through:    Safe Sex Practices: Use condoms consistently and correctly during sexual activity to reduce the risk of HIV transmission.    Regular Testing: Get tested for HIV regularly and encourage partners to do the same, ensuring early detection and treatment.    Pre-Exposure Prophylaxis (PrEP): Use PrEP medication if at high risk of HIV to reduce the likelihood of infection.    Avoid Sharing Needles: Do not share needles or syringes; use clean, sterile equipment for drug use.    Education and Awareness: Promote knowledge about HIV transmission and prevention methods to reduce stigma and encourage safe practices.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION B>5>b", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : HIV/AIDS : STIGMATIZATION OF PEOPLE LIVING WITH HIV/AIDS", "question": "Outline five symptoms that are usually associated with People Living with HIV/AIDS (PLWHA).", "images": [], "marking_scheme": "People Living with HIV/AIDS (PLWHA) may experience a range of symptoms, which can vary depending on the stage of the disease:    Acute Retroviral Syndrome (Early Stage): Shortly after infection, individuals may experience flu-like symptoms such as fever, sore throat, rash, and swollen lymph nodes. This is known as acute retroviral syndrome or primary HIV infection.    Persistent Cough and Shortness of Breath: As the disease progresses, PLWHA may develop persistent coughs and difficulty breathing, which can be indicative of opportunistic infections like Pneumocystis pneumonia (PCP).    Chronic Diarrhea: Ongoing diarrhea that does not resolve with standard treatments can be a symptom of HIV/AIDS, often resulting from gastrointestinal infections or complications.    Weight Loss and Wasting: Significant, unexplained weight loss and wasting are common, reflecting the body's inability to maintain nutrition due to the illness.    Skin Changes: PLWHA might experience skin issues such as persistent rashes, lesions, or sores. These can be symptoms of opportunistic infections or other HIV-related conditions affecting the skin.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION B>6>a", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFORTS OF GOVERNMENT AND INDIVIDUALS IN STOPPING HUMAN TRAFFICKING", "question": "List three agencies responsible for curtailing human trafficking in your country.", "images": [], "marking_scheme": "In Nigeria, three key agencies responsible for curtailing human trafficking are:    National Agency for the Prohibition of Trafficking in Persons (NAPTIP): This agency is tasked with enforcing laws against human trafficking, investigating trafficking cases, and providing support to victims.    Nigeria Immigration Service (NIS): The NIS plays a crucial role in monitoring and regulating immigration to prevent trafficking, including screening and arresting suspected traffickers at border points.    Nigeria Police Force (NPF): The NPF conducts investigations, arrests traffickers, and collaborates with other agencies in tackling human trafficking and related crimes.", "marks": "3", "difficulty": "1"}, {"id": "theory>Civic Education>2024>SECTION B>6>b", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Outline six problems associated with human trafficking in your country.", "images": [], "marking_scheme": "Human trafficking in Nigeria poses several significant problems:    Exploitation of Victims: Victims often face severe exploitation, including forced labor, sexual slavery, and domestic servitude. They are frequently subjected to physical and emotional abuse, leading to long-term trauma and health issues.    Lack of Legal Protections: Despite laws against trafficking, enforcement can be inconsistent. Corruption and inadequate legal frameworks sometimes hinder efforts to prosecute traffickers and protect victims effectively.    Health Risks: Victims are at high risk of contracting sexually transmitted infections (STIs), including HIV/AIDS, due to forced sex work and poor living conditions. They also face mental health challenges, including depression and anxiety.    Stigmatization and Marginalization: Trafficking victims often experience social stigma and isolation, making it difficult for them to reintegrate into society. This marginalization can hinder their recovery and access to support services.    Impoverished Communities: Traffickers prey on vulnerable individuals from impoverished communities. Economic instability and lack of education opportunities contribute to the cycle of trafficking, as individuals seek better prospects abroad.    Weak Victim Support Systems: There is a shortage of comprehensive support services, including shelters, counseling, and rehabilitation programs. This inadequacy limits the ability to assist victims fully and reintegrate them into society.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION C>7>a", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "a", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW", "question": "Explain the rule of law.", "images": [], "marking_scheme": "The rule of law is a principle that ensures all individuals and institutions are subject to and accountable under the law, which is fairly applied and enforced. It mandates that laws must be clear, publicized, and applied consistently, protecting fundamental rights and liberties. No one is above the law, including lawmakers, law enforcement, and judiciary members. The rule of law promotes justice by providing a legal framework for resolving disputes and holding individuals accountable for unlawful actions, thereby preventing arbitrary governance and safeguarding democratic principles.", "marks": "3", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION C>7>b", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "b", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : IMPORTANCE OF RULE OF LAW", "question": "Highlight six conditions that can enhance adherence to the principles of rule of law in a democracy.", "images": [], "marking_scheme": "Adhering to the principles of the rule of law in a democracy requires several key conditions:    Independent Judiciary: A robust and impartial judiciary is crucial for upholding the rule of law. Judges must be free from political influence and corruption to ensure fair and unbiased legal proceedings.    Transparent Legal Framework: Laws should be clear, accessible, and well-publicized, allowing citizens to understand their rights and obligations. Transparency in the legal system fosters trust and compliance.    Accountability and Checks and Balances: Effective mechanisms for holding public officials and institutions accountable are essential. This includes having systems in place to address abuses of power and ensure that all actions are within legal bounds.    Effective Law Enforcement: Law enforcement agencies must operate within the law and uphold legal standards. Training, oversight, and proper procedures are needed to prevent abuse and ensure justice is served.    Citizen Engagement and Awareness: Educating citizens about their rights and responsibilities promotes greater adherence to the rule of law. Active participation in civic matters helps maintain a culture of legality and accountability.    Strong Institutions and Civil Society: Robust institutions, including regulatory bodies and civil society organizations, support the rule of law by monitoring compliance, advocating for legal reforms, and providing support for victims of injustice.", "marks": "12", "difficulty": "2"}, {"id": "theory>Civic Education>2024>SECTION C>8", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "8", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : DEMOCRACY, RULE OF LAW AND NATIONAL DEVELOPMENT : PROBLEMS OF DEMOCRACY", "question": "Identify five challenges facing democracy in West Africa", "images": [], "marking_scheme": "Democracy in West Africa faces several significant challenges:    Political Instability: Frequent coups, civil unrest, and conflicts undermine democratic processes and create an environment of uncertainty. Political instability disrupts governance and deters development.    Corruption: High levels of corruption weaken democratic institutions and erode public trust. Corruption in both public and private sectors hampers effective governance, resource allocation, and equitable development.    Weak Institutions: Many West African democracies struggle with weak institutions, including ineffective judicial systems, law enforcement, and regulatory bodies. This undermines the rule of law and hinders accountability.    Limited Press Freedom: In some countries, media censorship and harassment of journalists restrict freedom of expression. This limits the ability to hold leaders accountable and reduces transparency.    Electoral Fraud and Manipulation: Issues such as vote-buying, electoral violence, and tampering with election results compromise the integrity of democratic processes. These practices undermine public confidence in electoral outcomes and democratic legitimacy.", "marks": "15", "difficulty": "3"}, {"id": "theory>Civic Education>2024>SECTION C>9", "subject": "Civic Education", "year": "2024", "type": "Theory", "sub_label": "9", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : MEANING OF CONSTITUTED AUTHORITY", "question": "Highlight five scopes of the constitution.", "images": [], "marking_scheme": "The scope of a constitution encompasses several critical areas that define and govern a country's legal and political framework:    Fundamental Rights and Freedoms: Constitutions typically outline the basic rights and liberties guaranteed to all citizens, such as freedom of speech, religion, and assembly. These provisions protect individuals from abuses and ensure equal treatment under the law.    Structure of Government: Constitutions establish the organization and functions of government institutions, including the executive, legislative, and judicial branches. This scope details how these branches interact, their powers, and their responsibilities, ensuring a balance of power.    Electoral Systems: The constitution sets the rules for conducting elections, including the processes for electing representatives, political party regulations, and the mechanisms for ensuring fair and transparent voting.    Amendment Procedures: Constitutions include provisions for their own amendment, outlining the process and requirements for making changes. This allows the constitution to evolve in response to changing needs while providing stability and continuity.    Federal or Unitary Structure: The constitution defines the division of powers between central and regional governments in federal systems or the concentration of power in unitary systems. This scope determines the allocation of authority and the relationship between different levels of government.", "marks": "15", "difficulty": "2"}, {"id": "theory>Civic Education>2025>SECTION A>1>a", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "a", "group": "CLOSENESS", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "Outline three ways negative media reportage affects responsible parenthood.", "images": [], "marking_scheme": "- Undermining of Moral Values: Many forms of negative media tend to portray and even celebrate morally questionable actions-such as casual sexual encounters, substance abuse, and defiance of authority figures. Such portrayals can conflict sharply with the ethical and moral teachings parents strive to impart to their children.    - Disruption of Academic Engagement: When children spend excessive time consuming non-educational media-especially entertainment that offers no intellectual benefit-it can interfere with their concentration, reduce study time, and ultimately impair academic achievement.    - Misrepresentation of Real Life: The media often projects distorted images of success, beauty, and happiness, which can lead children to develop unrealistic standards and aspirations. This makes it more challenging for parents to help them embrace authenticity, humility, and a healthy sense of self-worth.    - Promotion of Aggressive Behaviour:  Many media programs, especially video games and action films, normalize violence and aggression as acceptable ways to solve problems. This can influence children to become desensitized to violence or imitate aggressive behavior, making it harder for parents to instill values like empathy, patience, and peaceful conflict resolution.    - Weakening of Family Bonds:  Constant media consumption—especially via personal devices—can reduce meaningful interaction between children and their family members. Over time, this can erode communication, reduce emotional closeness, and make it harder for parents to guide their children through shared values and experiences.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION A>1>b", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : RESPONSIBLE PARENTHOOD : ROLES OF RESPONSIBLE PARENTS", "question": "Outline three ways parents can equip their children against negative media influence.", "images": [], "marking_scheme": "- Promoting Media Literacy: Parents should actively educate their children on how to interpret and evaluate media content with discernment. By teaching them to identify underlying messages, stereotypes, exaggerations, and misinformation, children become equipped to question and analyze what they consume rather than passively accepting it as truth.    - Establishing Clear Media Guidelines: Setting reasonable boundaries around screen time and monitoring the type of content children are exposed to enables parents to safeguard their children from harmful or inappropriate media. These boundaries help create a structured media environment that supports healthy development.    - Modeling Responsible Media Use: Children often emulate adult behavior. Parents must therefore demonstrate thoughtful and ethical media consumption themselves. By showing critical thinking, self-restraint, and integrity in their own choices, parents set a powerful example that influences their children's attitudes and habits.    – Encouraging Alternative Activities:  Parents should introduce and support engaging alternatives to screen time, such as reading, sports, arts, or family outings. These activities not only reduce media dependency but also promote creativity, social skills, and overall well-being.    – Maintaining Open Communication:  Creating an atmosphere where children feel safe discussing what they see or hear in the media allows parents to guide them through confusing or inappropriate content. This ongoing dialogue builds trust and helps children develop critical thinking skills with parental input.    – Using Media as a Teaching Tool:  Instead of banning media entirely, parents can co-view certain programs and use them as opportunities to teach values, correct misconceptions, and stimulate meaningful conversations. This transforms passive media consumption into an interactive learning experience.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION A>2>a", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : MEANING OF CITIZENSHIP EDUCATION", "question": "State five conditions an alien must fulfil to become a citizen of a country.", "images": [], "marking_scheme": "- Lawful Entry and Residency Compliance: To qualify for citizenship, the individual must have entered the country through legal channels and maintained continuous lawful residence for the duration specified by the nation's immigration regulations. This ensures respect for national laws from the outset.    - Demonstration of Good Moral Conduct: The applicant is required to exhibit a history of good character, typically verified through background checks. This means having no criminal convictions or involvement in activities that could endanger public safety, order, or national integrity.    - Language Proficiency Requirement: Most countries expect aspiring citizens to have a functional grasp of the national language. This ability promotes social integration, effective communication, and participation in civic duties.    - Familiarity with National Heritage and Legal Framework: Applicants must demonstrate an understanding of the country's traditions, cultural values, political structure, constitution, and laws. This helps ensure that they can function responsibly and respectfully within the society.    - Pledge of Loyalty through Oath: As a final step, the individual must formally swear an oath of allegiance, committing to uphold and remain loyal to their new country. This often includes renouncing previous national loyalties to affirm undivided allegiance.    – Minimum Residency Duration:  Many countries mandate that applicants must have lived within their borders for a specific number of years—often ranging from three to ten—before applying for citizenship. This residency period allows the individual to become familiar with societal norms, integrate into the community, and demonstrate long-term commitment.    – Financial Stability and Self-Sufficiency:  Applicants are typically required to prove that they can support themselves without becoming a burden on the state. Evidence of stable income, employment, or assets is often used to assess whether the person can contribute productively to the economy.    – Age and Mental Competence Criteria:  Most nations specify a minimum age—usually 18 years—for citizenship applicants, along with the expectation that the individual possesses sound mental judgment. This ensures that the applicant can fully understand and accept the responsibilities of citizenship.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION A>2>b", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : CITIZENSHIP AND NATIONALISM : IDENTIFICATION OF LOCAL AND WORLD CIVIC PROBLEMS", "question": "Highlight five ways responsible citizens can show loyalty to their country.", "images": [], "marking_scheme": "- Upholding National Unity and Harmony: One of the highest forms of loyalty a citizen can demonstrate is the active promotion of peace, inclusiveness, and national cohesion. This involves rejecting divisive practices such as tribalism, hate speech, and discrimination, while embracing dialogue, tolerance, and mutual respect among all citizens, regardless of their background.    - Exercising the Right to Vote: Loyal citizens participate in the democratic process by voting in elections. This not only ensures that capable and accountable leaders are chosen but also reinforces the stability and legitimacy of democratic institutions.    - Adherence to Laws and Legal Norms: Obeying the laws of the land-whether civil, criminal, or administrative-is a fundamental expression of national loyalty. It reflects a citizen's respect for justice, order, and the common good, contributing to a peaceful and stable society.    – Participating in National Service and Volunteering:  Loyal citizens willingly contribute their time, skills, or resources to national development through community service, civic duties, or national service programs. Such contributions promote collective progress and strengthen the spirit of patriotism and shared responsibility.    – Defending the Nation's Interests:  Citizens show loyalty by standing up for their country's values, sovereignty, and image—whether through military service, diplomacy, or simply promoting national pride. This includes responsibly addressing misinformation about the country and supporting initiatives that protect its integrity and well-being.    – Respecting National Symbols and Institutions:  Demonstrating loyalty involves showing reverence for national symbols like the flag, anthem, and constitution, as well as institutions such as the presidency, judiciary, and legislature. This respect promotes unity and reinforces the legitimacy of national authority and governance.    – Paying Taxes and Fulfilling Civic Obligations:  A loyal citizen supports national development by paying taxes, which fund public services such as education, healthcare, security, and infrastructure. Meeting civic obligations like census participation or jury duty (where applicable) also reflects commitment to national progress.    – Promoting Economic Patriotism:  Citizens display loyalty by supporting locally made goods and services, investing in the national economy, and discouraging practices that harm local industries. Economic patriotism helps strengthen national self-reliance and reduces dependence on foreign markets.    – Promoting Social Justice and Equity:  True loyalty is expressed in the defense of fairness, equity, and justice for all citizens. This includes standing against oppression, corruption, and abuse of power, and advocating for the rights and dignity of marginalized or vulnerable groups within the nation.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION A>3>a", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : TRAFFIC REGULATIONS : THE ROLES OF THE INDIVIDUAL AND GOVERNMENT IN MAINTAINING TRAFFIC REGULATIONS", "question": "Fifteen-year-old Timmy was receiving a call while driving. He ran a red light and got hit by a truck.  Identify three key traffic related issues highlighted in the above scenario.", "images": [], "marking_scheme": "- Driving Below Legal Age: At just fifteen years old, Timmy is not legally eligible to operate a vehicle. His action constitutes a significant breach of traffic laws that specify the minimum legal age for driving.    - Mobile Phone Distraction While Driving: Answering or making phone calls while behind the wheel poses a serious distraction. It impairs concentration and slows reaction time, making it a leading factor in many road accidents.    - Ignoring Traffic Lights: Failing to obey a red traffic signal is a clear violation of road safety regulations. Such behavior endangers not only the driver but also other motorists and pedestrians by increasing the likelihood of collisions.    – Overloading Vehicles:  Carrying more passengers or cargo than a vehicle is designed for compromises the vehicle's balance, braking efficiency, and overall safety. Overloading increases the risk of tire bursts, loss of control, and severe accidents.    – Speeding Beyond the Limit:  Exceeding the posted speed limit is a dangerous traffic offence. It reduces the driver's ability to respond to sudden obstacles or changes in road conditions and significantly increases the severity of accidents when they occur.    – Driving Under the Influence (DUI):  Operating a vehicle while under the influence of alcohol or drugs impairs judgment, coordination, and reaction time. It is one of the leading causes of fatal road crashes and is punishable by strict penalties in most jurisdictions.    – Not Wearing a Seatbelt:  Failure to wear a seatbelt increases the risk of serious injury or death in the event of a crash. Seatbelts are basic safety features designed to protect both drivers and passengers, and not using them is both unlawful and reckless.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION A>3>b", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : HUMAN RIGHTS : MEANING AND HISTORICAL BACKGROUND OF THE UNIVERSAL DECLARATION OF HUMAN RIGHTS (UDHR)", "question": "State three measures required to prevent the occurence of such incident.", "images": [], "marking_scheme": "- Rigorous Implementation of Minimum Driving Age Laws: Law enforcement agencies should diligently uphold regulations that prohibit individuals below the legal age from driving. This includes regular checks and strict penalties to deter underage driving and enhance road safety.    - Comprehensive Public Education Initiatives: Ongoing awareness programs, especially through schools, social media, and community outreach, are essential to educate the public-particularly young drivers-about the dangers of distractions like mobile phone use and the serious consequences of ignoring traffic signals.    - Active Parental Supervision and Guidance: Parents play a crucial role in promoting road safety by ensuring their children do not have unsupervised or unauthorized access to vehicles. They must also engage in meaningful conversations to teach responsible behavior and respect for traffic laws.    – Installation of Road Safety Surveillance Technologies:  Deploying traffic cameras, speed limit monitors, and red-light enforcement systems at strategic locations can significantly deter reckless driving. These technologies assist in monitoring compliance, identifying offenders, and enhancing accountability on the roads.    – Stricter Licensing and Testing Procedures:  Authorities should adopt more rigorous testing for driving licenses, ensuring that only well-trained, knowledgeable, and responsible individuals are certified. This includes thorough assessment of road signs, defensive driving skills, and hazard perception.    – Enforcement of Distracted Driving Laws:  Governments should strictly enforce laws against mobile phone usage while driving. This includes issuing fines, license points, or temporary suspension for offenders. Consistent enforcement sends a strong message that distracted driving will not be tolerated.    – Collaboration with Transportation Stakeholders:  Effective road safety demands cooperation between law enforcement, transport unions, schools, NGOs, and local governments. Joint efforts can lead to the creation of targeted interventions, such as youth driving clubs, road safety days, and driver retraining programs.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION B>4", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "4", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : YOUTH EMPOWERMENT : EFFORTS OF GOVERNMENT TOWARDS YOUTH EMPOWERMENT", "question": "Describe how five government initiatives have contributed to the empowerment of youthsin your country.", "images": [], "marking_scheme": "- Youth Empowerment and Skills Acquisition Programmes (YESAP): These programmes are designed to equip young people with hands-on vocational and technical skills in areas such as tailoring, carpentry, welding, and information and communication technology (ICT). By acquiring these practical skills, many youths are able to start their own businesses or secure meaningful employment, thereby reducing the rate of youth unemployment and promoting economic self-sufficiency.    - National Youth Service Corps (NYSC): The NYSC scheme serves as a platform for promoting national unity and integration by posting recent graduates to regions outside their home states. In addition to fostering cross-cultural understanding, the programme offers participants opportunities to engage in community development projects, assume leadership responsibilities, and access career prospects, ultimately enhancing their confidence and professional competence.    - Government Agricultural Empowerment Initiatives: Through schemes like the Youth Farm Lab and N-Power Agro, the government provides agricultural training, inputs, equipment, and funding to young people interested in farming. These programmes aim to make agriculture more appealing to the youth, empower them to be self-sustaining, and contribute significantly to food production and national food security.    - N-Power Programme: N-Power is a comprehensive employment and capacity-building initiative that targets unemployed graduates and non-graduates. Participants are placed in critical sectors such as education, health, and technology, where they gain practical work experience and receive monthly stipends. The programme enhances their employability, boosts their confidence, and prepares them for long-term career paths or entrepreneurship.    - Digital Literacy and Innovation Centres: As part of efforts to prepare young people for the demands of the digital age, the government has set up ICT hubs and innovation centres across the country. These facilities offer training in areas like coding, artificial intelligence, digital marketing, and robotics. By gaining these 21st-century skills, youths are better positioned to compete in the global digital economy and access a broader range of employment opportunities.    – Student Industrial Work Experience Scheme (SIWES):  SIWES is a practical training programme designed for students in tertiary institutions, particularly those in science, engineering, technology, and vocational courses. By placing them in relevant industries, the scheme bridges the gap between theoretical knowledge and real-world application, preparing them for the workforce and enhancing their technical competence.    – Graduate Internship Scheme (GIS):  The GIS provides unemployed graduates with temporary job placements in reputable organisations. During the internship period, participants acquire workplace skills, improve their CVs, and build professional networks. The aim is to boost their chances of securing full-time employment or starting their own ventures after the programme.    – Youth Entrepreneurship Support (YES) Programme:  Organised by the Bank of Industry, the YES Programme provides young entrepreneurs with business training, mentorship, and access to funding. It targets innovative and scalable ideas, helping youths transform concepts into viable enterprises. This initiative fosters a culture of entrepreneurship and reduces dependence on white-collar jobs.    – Creative Industry Financing Initiative (CIFI):  Recognising the talents of Nigerian youths in music, film, fashion, and other creative sectors, the CIFI—backed by the Central Bank of Nigeria—offers financial support to startups and SMEs in the creative industry. This programme empowers youths to monetise their talents, generate income, and contribute to Nigeria's cultural and economic development.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION B>5>a", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : CONSEQUENCES OF DRUG ABUSE", "question": "Musa, a high school student recently joined a group of friends who offered him pills believed to enhance relaxation and enjoyment.    Enumerate five consequences Musa could face if he agrees to take the pills.", "images": [], "marking_scheme": "- Health Hazards: Taking an unfamiliar substance poses serious health risks. These may include unexpected side effects, the danger of overdose, or harmful interactions with other medications Mosi might be using. Such risks can result in lasting physical or psychological harm.    - Legal Repercussions: Being in possession of, or using, illegal drugs can have severe legal consequences. These may range from fines and a criminal record to arrest and imprisonment, potentially damaging Mosi's future prospects.    - Compromised Decision-Making: Substance use can impair Mosi's ability to think clearly and make sound judgments. This may lead to irresponsible behavior, strained relationships, poor academic choices, or dangerous actions that put his safety and that of others at risk.    - Risk of Addiction: Even casual or experimental use of certain pills can lead to dependence. Addiction can have long-term consequences on Mosi's mental and physical health, relationships, and general well-being, making it difficult to regain control over his life.    - Decline in Academic Performance: The use of such substances can reduce Mosi's ability to concentrate, retain information, and perform well in school. This could negatively affect his grades, limit future educational or career opportunities, and undermine the effort he has already invested in his studies.    – Exposure to Peer Pressure and Negative Influences:  Engaging in drug use can draw Mosi into circles where substance abuse is normalized or even encouraged. This increases the risk of repeated use, deeper involvement in risky behaviours, and greater resistance to positive influence from family or mentors.    – Damage to Reputation and Trust:  Being associated with drug use can tarnish Mosi's reputation among teachers, peers, family members, and future employers. Trust may be broken, and rebuilding credibility in both personal and academic settings can be a difficult and lengthy process.    – Financial Strain:  Sustaining a drug habit often becomes expensive over time. Mosi might start spending money meant for other needs or become tempted to steal or borrow excessively, leading to debt or financial dependence.    – Increased Risk of Accidents or Injury:  Drugs can slow reaction time, distort perception, and reduce coordination. If Mosi were to drive, walk near traffic, swim, or operate machinery while under the influence, he could seriously harm himself or others through accidents.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION B>5>b", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : DRUGS AND DRUG ABUSE : BEHAVIOURS OF DRUG ADDICTS", "question": "Highlight five steps Musa could take to resist the offer.", "images": [], "marking_scheme": "- Give a Firm and Clear Refusal: Mosi should confidently say \"no\" without hesitation or apology. A direct response shows strength and leaves no room for pressure or confusion.    - Communicate His Concerns: He can express his reasons for refusing, such as the health risks, legal consequences, and negative impact on his future. Explaining his stance calmly may also discourage further persuasion.    - Recommend Positive Alternatives: Instead of just rejecting the offer, Mosi can suggest healthier and more enjoyable ways to spend time together-like playing games, watching movies, or engaging in a hobby-thus keeping the social bond intact without resorting to substance use.    - Reach Out for Guidance and Encouragement: If Mosi feels overwhelmed or unsure, he should confide in someone he trusts-a parent, teacher, friend, or school counselor. Getting support can help him stay firm and emotionally grounded.    - Stay Focused on His Aspirations: Reminding himself of his long-term goals-such as excelling in school, pursuing a career, or staying healthy-can strengthen his resolve. Recognizing that drug use could derail these ambitions will reinforce his decision to say no.    – Avoid Risky Situations and Triggers:  Mosi should steer clear of places, events, or people where he's likely to be exposed to drugs or pressured into trying them. Choosing his environment wisely reduces temptation and the likelihood of being caught off guard.    – Use Humour or Distraction to Defuse Pressure:  Sometimes a light joke or a quick change of topic can ease the tension and shift the conversation away from drugs. For example, Mosi might say something like, \"No thanks—I like my brain just the way it is!\" This keeps things friendly while still drawing a firm boundary.    – Practice Refusal Skills in Advance:  Rehearsing how to say \"no\" through role-playing or self-talk can make Mosi more confident when the situation arises. Being prepared helps him stay calm and assertive instead of panicking or giving in under pressure.    – Surround Himself with Positive Influences:  Choosing friends who share his values and support healthy choices can make all the difference. With a strong, supportive peer group, Mosi is less likely to feel isolated or tempted and more likely to feel validated in his decision.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION B>6>a", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : CAUSES OF HUMAN TRAFFICKING", "question": "Naje escaped from a conflict zone and is now staying in a refugee camp.  Enumerate seven ways her displacement could increase her risk of being trafficked.", "images": [], "marking_scheme": "- Absence of Legal Protection: Refugees often flee without valid identification or legal status, leaving them without access to basic rights or protections. This makes it easier for traffickers to exploit them, knowing they are less likely to report abuse due to fear of arrest or deportation.    - Family Separation and Isolation: Being separated from loved ones or traditional support systems increases emotional distress and leaves refugees without guidance or protection. Traffickers exploit this isolation, targeting those who are alone and emotionally vulnerable.    - Extreme Poverty and Urgent Need: The scarcity of essentials such as food, shelter, healthcare, and money can drive refugees to make desperate choices. This desperation may lead them to accept offers of help or work from traffickers without fully understanding the danger.    - Lack of Education and Information: Many displaced individuals may not have access to education or awareness programs that could help them recognize signs of trafficking. Without this knowledge, they are more susceptible to deception and manipulation.    - Poorly Managed or Unregulated Refugee Camps: In camps where there is little oversight or accountability, traffickers can operate with ease. Inadequate infrastructure, lack of personnel, and disorganization allow them to move in and target vulnerable people.    - Inadequate Law Enforcement Presence: Limited or ineffective policing in refugee areas gives traffickers the freedom to act without fear of being caught. The absence of strong legal systems or enforcement makes it difficult to protect at-risk individuals.    - Misplaced Trust in Strangers: Traffickers often disguise themselves as friendly helpers, aid workers, or job recruiters. Refugees, eager for assistance and stability, may unknowingly place their trust in these individuals, putting themselves at serious risk of exploitation.    – Language Barriers and Communication Challenges:  Many refugees find themselves in countries where they do not speak the local language fluently. This hinders their ability to seek help, understand legal processes, or detect warning signs in conversations—making it easier for traffickers to manipulate or deceive them.    – Gender-Based Vulnerabilities:  Women and girls, in particular, face heightened risks of trafficking for purposes such as forced prostitution, early marriage, or domestic servitude. In refugee contexts, where gender-based violence is often widespread, traffickers exploit these vulnerabilities with impunity.    – Lack of Access to Safe and Legal Employment:  Without legal documentation or work permits, refugees are often barred from formal employment. This forces many into the informal or underground job market, where traffickers pose as employers and exploit them with false promises of wages, shelter, or documentation.    – Breakdown of Social and Legal Institutions:  In war-torn or disaster-affected regions, basic systems of justice, protection, and social welfare may collapse. In such environments, traffickers operate freely, knowing that there are few mechanisms in place to detect or prevent their actions.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION B>6>b", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "EMERGING ISSUES IN THE SOCIETY : HUMAN TRAFFICKING : EFFECTS AND CONSEQUENCES OF HUMAN TRAFFICKING", "question": "Outline four protection strategies that governement can adopt to protect Naje from being trafficked.", "images": [], "marking_scheme": "- Strengthen Security Within Refugee Camps: Governments and international agencies should deploy well-trained security personnel to refugee settlements to actively monitor activities, prevent traffickers from gaining access, and ensure the safety of vulnerable individuals. Regular patrols and surveillance can deter criminal networks from operating in these spaces.    - Launch Targeted Awareness Campaigns: Refugees should be educated about the tactics traffickers use, as well as the signs of exploitation. This can be done through posters, workshops, drama, and multilingual sessions. Equipping refugees with this knowledge empowers them to protect themselves and others.    - Provide Legal Identity and Documentation: Refugees should be issued valid identification cards, temporary permits, or legal status documents. These reduce their vulnerability to exploitation by granting them access to essential services and protection under the law, and making it harder for traffickers to manipulate or threaten them.    - Establish Safe and Confidential Reporting Channels: Authorities and humanitarian organizations should set up accessible hotlines, help desks, or trusted personnel within camps where refugees can safely report suspicious behavior or trafficking attempts. These channels must be confidential, multilingual, and sensitive to the trauma of victims to encourage reporting without fear.    – Expand Access to Education and Vocational Training:  Providing formal and informal education, including vocational skills development, equips refugees—especially youth and women—with knowledge and tools for self-reliance. Education reduces vulnerability by increasing awareness and improving future job prospects, making refugees less likely to fall for exploitative offers.    – Facilitate Legal and Safe Employment Opportunities:  Governments and aid organizations should create pathways for refugees to access legal and dignified work. This includes work permits, job matching programs, and entrepreneurship support. When refugees can earn a living safely, they are less likely to be lured by traffickers offering deceptive employment.    – Strengthen International Cooperation and Border Monitoring:  Countries must collaborate across borders to track, investigate, and dismantle trafficking networks. Improved border controls, data sharing, and joint operations can prevent traffickers from smuggling refugees across borders undetected and hold perpetrators accountable.    – Support Psychosocial Services and Community Building:  Offering trauma counseling, social support groups, and community engagement activities helps refugees heal emotionally and rebuild a sense of belonging. When individuals feel supported and connected, they are more resilient to manipulation and less likely to fall into exploitative traps.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION C>7>a", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Identify five functions of local government.", "images": [], "marking_scheme": "- Provision of basic social services such as health centers, water supply, and waste disposal.    - Construction and maintenance of roads within the local area.    - Establishment and regulation of markets and motor parks.    - Collection of rates and levies (e.g., shop and tenement rates).    - Registration of births, deaths, and marriages.    – Primary Education Administration:  Local governments are responsible for building, equipping, and maintaining public primary schools, as well as recruiting and paying primary school teachers (often in collaboration with state authorities).    – Rural Development and Agricultural Support:  They support local farmers through agricultural extension services, provision of farming tools, seedlings, and veterinary services, thereby boosting food production and rural economic growth.    – Local Security and Vigilante Services:  Local governments help maintain law and order by supporting community policing initiatives and local vigilante groups, especially in areas where formal security presence is limited.    – Issuance of Local Business Licences:  They regulate small businesses by issuing licences and permits to operators of shops, kiosks, barbershops, and artisans, ensuring compliance with local standards and bylaws.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION C>7>b", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : STRUCTURE/TIERS OF GOVERNMENT", "question": "Outline five sources of local government revenue.", "images": [], "marking_scheme": "– Federal Government Allocation (Statutory Allocation):  This is the portion of national revenue distributed to local governments by the federal government. It is shared monthly based on a revenue-sharing formula and serves as a major source of income for local councils.    – State Government Grants or Subventions:  These are financial supports given by the state government to local governments to assist them in specific projects or to supplement their budgets, especially when internally generated revenue is low.    – Local Taxes and Rates (e.g., Tenement Rates, Radio/TV License Fees):  These are compulsory charges imposed on residents and businesses within the local area. Examples include tenement (property) rates and fees for owning a radio or TV. They are collected directly by the local council.    – Fines and Court Fees Collected from Customary Courts:  When local courts handle civil or minor criminal cases, the fines imposed and fees for legal processes are collected as revenue for the local government.    – Donations and Aids from NGOs, Individuals, or International Bodies:  These are voluntary financial or material supports provided by non-governmental organisations, philanthropists, or foreign partners to help the local government implement development projects or respond to emergencies.    – Proceeds from local business licenses and permits  Local governments generate revenue by issuing licenses and permits to operators of shops, markets, and small-scale enterprises.    – Earnings from motor parks and market stalls  Fees collected from traders and transport operators using markets and motor parks serve as a steady source of income.    – Rent from local government properties  Revenue is earned by leasing community halls, event centres, or government-owned buildings and land.    – Agricultural and produce fees  Levies on agricultural produce (e.g., farm gate fees, cattle market dues) provide funds especially in rural areas.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION C>8", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "8", "group": "", "topic": "NATIONAL ETHICS, DISCIPLINE, RIGHTS AND OBLIGATION : LAW AND ORDER : FEATURES OF LAW AND ORDER", "question": "Highlight five ways by which effective application of the rule of law can discourage arbitrary rule.", "images": [], "marking_scheme": "– Strengthens democratic governance:  The rule of law provides a legal framework that upholds free and fair elections, separation of powers, and checks and balances—ensuring that leaders are chosen and governed according to established laws.    – Builds public trust in institutions:  When laws are applied fairly and transparently, citizens develop confidence in public institutions like the police, judiciary, and legislature, fostering civic cooperation and stability.    – Attracts investment and supports economic growth:  A nation governed by predictable and enforceable laws creates a secure environment for businesses and investors, leading to job creation and economic development.    – Promotes peace and order in society:  The rule of law maintains social harmony by clearly defining acceptable behavior, settling disputes fairly, and punishing wrongdoing through due legal process rather than violence or personal revenge.    - Ensures equality before the law    - Promotes accountability    - Protects fundamental rights    - Limits abuse of power    - Encourages judicial independence", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION C>9>a", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "a", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : MEANING OF POPULAR PARTICIPATION", "question": "Define traditional mode of popular participation.", "images": [], "marking_scheme": "Traditional modes of popular participation are indigenous and culturally rooted ways through which members of a community take part in political and social decision-making. These methods are informal and based on long-standing customs and traditions, including practices such as village assemblies, age-grade groups, town hall meetings, and consultations with the council of elders.", "marks": "1", "difficulty": "3"}, {"id": "theory>Civic Education>2025>SECTION C>9>b", "subject": "Civic Education", "year": "2025", "type": "Theory", "sub_label": "b", "group": "", "topic": "GOVERNMENTAL SYSTEM AND PROCESSES : CIVIL SOCIETY AND POPULATION PARTICIPATION : THE NEED FOR POPULAR PARTICIPATION IN THE SOCIETY", "question": "Advance 6 benefits of traditional mode of popular participation.", "images": [], "marking_scheme": "- Culturally Appropriate: It aligns with the people's customs and beliefs, giving their involvement deeper significance.  - Broad Participation: It engages diverse groups within the community, including elders, women, and youth.  - Promotes Peaceful Settlements: Traditional systems encourage dialogue and agreement, helping to resolve disputes amicably.  - Community Trust: Decisions reached through these means are generally respected and accepted by locals.  - Low-Cost Approach: These methods typically require minimal resources and function without formal institutions.  - Strengthens Unity: Such participation nurtures communal bonds and a shared sense of identity.  – Preserves Indigenous Knowledge:  They maintain and transmit valuable cultural practices, histories, and governance wisdom across generations.    – Enhances Local Accountability:  Leaders are often directly answerable to the community, making them more responsive to local needs.  – Provides Quick Decision-Making:  Traditional systems often allow for faster resolutions without bureaucratic delays.  – Complements Modern Governance:  They can work alongside formal government structures to improve local governance and conflict resolution.", "marks": "1", "difficulty": "3"}];